    /// m65: synthesize the built-in stdlib generic enums
    /// `Result<T, E>` and `Option<T>` as TypeDecls so programs
    /// can reference them without an explicit `type` declaration.
    /// They flow through the same m61c generic-enum
    /// monomorphization path as user-declared generics: discovery
    /// walks call sites and field types, synthesis produces e.g.
    /// `Result_Int_String` / `Option_Int`, and the path-call
    /// constructor (`Result_Int_String::Ok(...)`) lights up
    /// automatically. Returned with synthetic spans (0,0); they
    /// never surface in diagnostics because templates with
    /// non-empty generics aren't lowered directly — only their
    /// concrete instantiations are.
    fn builtin_generic_type_decls() -> Vec<TypeDecl> {
        let span = hale_syntax::span::Span::new(0, 0);
        let mk_ident = |s: &str| Ident {
            name: s.to_string(),
            span,
        };
        let mk_t = |name: &str| TypeExpr::Named {
            path: QualifiedName {
                segments: vec![mk_ident(name)],
                span,
            },
            generic_args: Vec::new(),
            span,
        };
        let mk_param = |name: &str| GenericParam {
            name: mk_ident(name),
            bound: None,
            span,
        };
        let result_decl = TypeDecl {
            name: mk_ident("Result"),
            generics: vec![mk_param("T"), mk_param("E")],
            body: TypeDeclBody::Enum(vec![
                EnumVariant {
                    name: mk_ident("Ok"),
                    fields: vec![mk_t("T")],
                    span,
                },
                EnumVariant {
                    name: mk_ident("Err"),
                    fields: vec![mk_t("E")],
                    span,
                },
            ]),
            span,
        };
        let option_decl = TypeDecl {
            name: mk_ident("Option"),
            generics: vec![mk_param("T")],
            body: TypeDeclBody::Enum(vec![
                EnumVariant {
                    name: mk_ident("Some"),
                    fields: vec![mk_t("T")],
                    span,
                },
                EnumVariant {
                    name: mk_ident("None"),
                    fields: Vec::new(),
                    span,
                },
            ]),
            span,
        };
        vec![result_decl, option_decl]
    }


    /// m64: check that each generic param's declared bound (if
    /// any) is satisfied by the corresponding type arg. v0.1
    /// recognizes only the `Numeric` bound, which admits Int /
    /// Float / Decimal / Duration. Unknown bound names error
    /// clearly so future bounds (e.g., `Eq`, `Ord`,
    /// `ProjectionClass`) surface a gap rather than passing
    /// silently. Called from each synthesize_generic_* helper
    /// before substitution so the check fires on the same code
    /// path that produces the mangled name.
    fn check_generic_bounds(
        template_kind: &str,
        template_name: &str,
        params: &[GenericParam],
        args: &[TypeExpr],
    ) -> Result<(), CodegenError> {
        for (gp, arg) in params.iter().zip(args.iter()) {
            let bound = match &gp.bound {
                Some(b) => b,
                None => continue,
            };
            let bound_name = match bound {
                TypeExpr::Named { path, generic_args, .. }
                    if path.segments.len() == 1
                        && generic_args.is_empty() =>
                {
                    path.segments[0].name.as_str()
                }
                _ => {
                    return Err(CodegenError::Unsupported(format!(
                        "{} `{}`: bound on `{}` is not a simple \
                         named bound (only simple names like \
                         `Numeric` recognized at v0.1)",
                        template_kind, template_name, gp.name.name
                    )));
                }
            };
            match bound_name {
                "Numeric" => {
                    let ok = matches!(
                        arg,
                        TypeExpr::Primitive(
                            PrimType::Int
                                | PrimType::Float
                                | PrimType::Decimal
                                | PrimType::Duration,
                            _,
                        )
                    );
                    if !ok {
                        return Err(CodegenError::Unsupported(format!(
                            "{} `{}`: type arg for `{}` must satisfy \
                             `Numeric` bound (Int / Float / Decimal / \
                             Duration); got non-numeric",
                            template_kind, template_name, gp.name.name
                        )));
                    }
                }
                other => {
                    return Err(CodegenError::Unsupported(format!(
                        "{} `{}`: unrecognized bound `{}` on `{}` \
                         (only `Numeric` recognized at v0.1)",
                        template_kind, template_name, other, gp.name.name
                    )));
                }
            }
        }
        Ok(())
    }

    /// m61: produce the mangled name for a generic instantiation.
    /// `Box<Int>` → `"Box_Int"`, `Pair<Int, String>` →
    /// `"Pair_Int_String"`. Recurses into nested generics so
    /// `Box<Pair<Int, String>>` → `"Box_Pair_Int_String"`. Each
    /// arg must be a primitive or a non-generic user type at this
    /// milestone (or itself a generic instantiation, which mangles
    /// recursively).
    pub(crate) fn mangle_generic_name(
        template: &str,
        args: &[TypeExpr],
    ) -> Result<String, CodegenError> {
        let mut tokens: Vec<String> = Vec::with_capacity(args.len());
        for a in args {
            tokens.push(Self::type_expr_mangle_token(a)?);
        }
        Ok(format!("{}_{}", template, tokens.join("_")))
    }

    /// m61: produce a single-token mangle for one generic arg.
    /// Primitives use their canonical name (`Int`, `String`,
    /// ...); a non-generic Named ref uses the bare name; a
    /// generic ref recurses through `mangle_generic_name`.
    fn type_expr_mangle_token(t: &TypeExpr) -> Result<String, CodegenError> {
        match t {
            TypeExpr::Primitive(p, _) => match p {
                PrimType::Int => Ok("Int".into()),
                PrimType::Float => Ok("Float".into()),
                PrimType::Bool => Ok("Bool".into()),
                PrimType::String => Ok("String".into()),
                PrimType::Duration => Ok("Duration".into()),
                PrimType::Decimal => Ok("Decimal".into()),
                PrimType::Time => Ok("Time".into()),
                other => Err(CodegenError::Unsupported(format!(
                    "primitive `{:?}` as generic arg (m61 v0.1)",
                    other
                ))),
            },
            TypeExpr::Named { path, generic_args, .. }
                if path.segments.len() == 1 =>
            {
                if generic_args.is_empty() {
                    Ok(path.segments[0].name.clone())
                } else {
                    Self::mangle_generic_name(
                        &path.segments[0].name,
                        generic_args,
                    )
                }
            }
            other => Err(CodegenError::Unsupported(format!(
                "type form `{:?}` as generic arg (m61 v0.1 only \
                 supports primitives + named types)",
                other
            ))),
        }
    }

    /// m61: substitute generic param refs (`T`, `U`, ...) inside a
    /// `TypeExpr` per the supplied substitution map. Recurses into
    /// generic args, array elems, tuple parts, etc., so a body
    /// like `[T; 4]` substitutes to `[Int; 4]` correctly.
    fn substitute_type_expr(
        expr: &TypeExpr,
        subst: &BTreeMap<String, TypeExpr>,
    ) -> TypeExpr {
        match expr {
            TypeExpr::Named { path, generic_args, span }
                if path.segments.len() == 1
                    && generic_args.is_empty()
                    && subst.contains_key(&path.segments[0].name) =>
            {
                subst[&path.segments[0].name].clone()
            }
            TypeExpr::Named { path, generic_args, span } => TypeExpr::Named {
                path: path.clone(),
                generic_args: generic_args
                    .iter()
                    .map(|a| Self::substitute_type_expr(a, subst))
                    .collect(),
                span: span.clone(),
            },
            TypeExpr::Array { elem, size, span } => TypeExpr::Array {
                elem: Box::new(Self::substitute_type_expr(elem, subst)),
                size: size.clone(),
                span: span.clone(),
            },
            TypeExpr::Tuple(parts, span) => TypeExpr::Tuple(
                parts
                    .iter()
                    .map(|p| Self::substitute_type_expr(p, subst))
                    .collect(),
                span.clone(),
            ),
            TypeExpr::Projection { class, inner, span } => {
                TypeExpr::Projection {
                    class: *class,
                    inner: Box::new(Self::substitute_type_expr(inner, subst)),
                    span: span.clone(),
                }
            }
            other => other.clone(),
        }
    }

    /// m63: synthesize a concrete (non-generic) LocusDecl from
    /// a generic template + a tuple of resolved type args. The
    /// substitution walks every TypeExpr-bearing position in
    /// the locus's members:
    /// - Params block (ParamDecl.ty)
    /// - Bus block (Subscribe.ty + Publish.ty)
    /// - Lifecycle decls (params + ret + body let-ascriptions)
    /// - Fn methods (params + ret + body let-ascriptions)
    /// - Const decls (ty)
    /// - Nested Type decls (struct fields + enum variant fields)
    ///
    /// v0.1 limits: Mode, Failure, Closure, Contract members
    /// pass through unchanged. Generic loci using those
    /// surfaces would need m63b. The body walk for lifecycle /
    /// fn methods only substitutes let / let-tuple ascriptions
    /// (matching the m62 fn-body shallow substitution).
    fn synthesize_generic_locus_instantiation(
        template: &LocusDecl,
        type_args: &[TypeExpr],
        mangled_name: &str,
    ) -> Result<LocusDecl, CodegenError> {
        if template.generics.len() != type_args.len() {
            return Err(CodegenError::Unsupported(format!(
                "generic locus `{}`: expected {} type args, got {}",
                template.name.name,
                template.generics.len(),
                type_args.len()
            )));
        }
        Self::check_generic_bounds(
            "generic locus",
            &template.name.name,
            &template.generics,
            type_args,
        )?;
        let mut subst: BTreeMap<String, TypeExpr> = BTreeMap::new();
        for (gp, arg) in template.generics.iter().zip(type_args.iter()) {
            subst.insert(gp.name.name.clone(), arg.clone());
        }
        let new_members: Vec<LocusMember> = template
            .members
            .iter()
            .map(|m| Self::substitute_locus_member(m, &subst))
            .collect();
        Ok(LocusDecl {
            name: Ident {
                name: mangled_name.to_string(),
                span: template.name.span.clone(),
            },
            is_main: template.is_main,
            export: template.export,
            generics: Vec::new(),
            annotations: template.annotations.clone(),
            form: template.form.clone(),
            locality: template.locality.clone(),
            bounded: template.bounded,
            members: new_members,
            span: template.span.clone(),
        })
    }

    fn substitute_locus_member(
        member: &LocusMember,
        subst: &BTreeMap<String, TypeExpr>,
    ) -> LocusMember {
        match member {
            LocusMember::Params(pb) => LocusMember::Params(ParamsBlock {
                params: pb
                    .params
                    .iter()
                    .map(|p| ParamDecl {
                        name: p.name.clone(),
                        ty: p.ty.as_ref().map(|t| {
                            Self::substitute_type_expr(t, subst)
                        }),
                        init: p.init.clone(),
                        span: p.span.clone(),
                    })
                    .collect(),
                span: pb.span.clone(),
            }),
            LocusMember::Bus(bb) => LocusMember::Bus(BusBlock {
                members: bb
                    .members
                    .iter()
                    .map(|bm| match bm {
                        BusMember::Subscribe { subject, handler, ty, key_filter, span } => {
                            BusMember::Subscribe {
                                subject: subject.clone(),
                                handler: handler.clone(),
                                ty: ty.as_ref().map(|t| {
                                    Self::substitute_type_expr(t, subst)
                                }),
                                key_filter: key_filter.clone(),
                                span: span.clone(),
                            }
                        }
                        BusMember::Publish { subject, ty, alias, span } => {
                            BusMember::Publish {
                                subject: subject.clone(),
                                ty: ty.as_ref().map(|t| {
                                    Self::substitute_type_expr(t, subst)
                                }),
                                alias: alias.clone(),
                                span: span.clone(),
                            }
                        }
                    })
                    .collect(),
                span: bb.span.clone(),
            }),
            LocusMember::Lifecycle(lc) => LocusMember::Lifecycle(
                LifecycleDecl {
                    kind: lc.kind,
                    params: lc
                        .params
                        .iter()
                        .map(|p| Param {
                            name: p.name.clone(),
                            ty: Self::substitute_type_expr(&p.ty, subst),
                            default: p.default.clone(),
                            span: p.span.clone(),
                        })
                        .collect(),
                    ret: lc
                        .ret
                        .as_ref()
                        .map(|t| Self::substitute_type_expr(t, subst)),
                    unbounded: lc.unbounded,
                    body: Self::substitute_block_type_ascriptions(
                        &lc.body, subst,
                    ),
                    span: lc.span.clone(),
                },
            ),
            LocusMember::Fn(fd) => LocusMember::Fn(FnDecl {
                name: fd.name.clone(),
                generics: fd.generics.clone(),
                params: fd
                    .params
                    .iter()
                    .map(|p| Param {
                        name: p.name.clone(),
                        ty: Self::substitute_type_expr(&p.ty, subst),
                        default: p.default.clone(),
                        span: p.span.clone(),
                    })
                    .collect(),
                ret: fd
                    .ret
                    .as_ref()
                    .map(|t| Self::substitute_type_expr(t, subst)),
                fallible: fd
                    .fallible
                    .as_ref()
                    .map(|t| Self::substitute_type_expr(t, subst)),
                // @ffi is only valid on top-level free fns at
                // Stage 1, never on locus members — but copy the
                // field through for shape uniformity.
                ffi: fd.ffi.clone(),
                export: fd.export,
                unbounded: fd.unbounded,
                body: Self::substitute_block_type_ascriptions(
                    &fd.body, subst,
                ),
                span: fd.span.clone(),
            }),
            LocusMember::Const(c) => LocusMember::Const(ConstDecl {
                name: c.name.clone(),
                ty: Self::substitute_type_expr(&c.ty, subst),
                value: c.value.clone(),
                span: c.span.clone(),
            }),
            // Mode, Failure, Closure, Contract, Type pass through
            // unchanged at v0.1; m63b can extend them when a
            // workload exercises generic loci that use those
            // surfaces.
            other => other.clone(),
        }
    }

    /// m62: convert a CodegenTy back to a TypeExpr for the
    /// generic-fn inference path. The resulting TypeExpr is used
    /// to mangle the instantiation name and to substitute into
    /// the template's body — both purely structural operations,
    /// so the synthetic spans are fine.
    fn codegen_ty_to_type_expr(
        t: &CodegenTy,
    ) -> Result<TypeExpr, CodegenError> {
        // Synthetic span for the synthesized TypeExpr — these
        // never surface in user-visible diagnostics because m62
        // structural ops only inspect shape, not source location.
        let span = hale_syntax::span::Span::new(0, 0);
        match t {
            CodegenTy::Int => Ok(TypeExpr::Primitive(PrimType::Int, span)),
            CodegenTy::Float => {
                Ok(TypeExpr::Primitive(PrimType::Float, span))
            }
            CodegenTy::Bool => Ok(TypeExpr::Primitive(PrimType::Bool, span)),
            CodegenTy::String => {
                Ok(TypeExpr::Primitive(PrimType::String, span))
            }
            CodegenTy::Duration => {
                Ok(TypeExpr::Primitive(PrimType::Duration, span))
            }
            CodegenTy::Decimal => {
                Ok(TypeExpr::Primitive(PrimType::Decimal, span))
            }
            CodegenTy::Time => Ok(TypeExpr::Primitive(PrimType::Time, span)),
            CodegenTy::TypeRef(name) | CodegenTy::Enum(name) => {
                Ok(TypeExpr::Named {
                    path: QualifiedName {
                        segments: vec![Ident {
                            name: name.clone(),
                            span,
                        }],
                        span,
                    },
                    generic_args: Vec::new(),
                    span,
                })
            }
            other => Err(CodegenError::Unsupported(format!(
                "codegen_ty_to_type_expr: form `{:?}` not supported \
                 (m62 v0.1 limits inference to primitives + named \
                 types as generic args)",
                other
            ))),
        }
    }

    /// m62: structurally walk a declared TypeExpr against an
    /// actual CodegenTy, recording bindings for any generic
    /// param refs. `params` names which idents in the TypeExpr
    /// represent generic params (vs. concrete user types).
    /// Errors if a param binds to multiple distinct types
    /// (inconsistent inference).
    fn unify_generic_param_bindings(
        declared: &TypeExpr,
        actual: &CodegenTy,
        params: &BTreeSet<String>,
        bindings: &mut BTreeMap<String, TypeExpr>,
    ) -> Result<(), CodegenError> {
        // Generic-param ref: bind to actual.
        if let TypeExpr::Named {
            path, generic_args, ..
        } = declared
        {
            if path.segments.len() == 1
                && generic_args.is_empty()
                && params.contains(&path.segments[0].name)
            {
                let bound = Self::codegen_ty_to_type_expr(actual)?;
                let name = &path.segments[0].name;
                if let Some(prior) = bindings.get(name) {
                    if prior != &bound {
                        return Err(CodegenError::Unsupported(format!(
                            "generic param `{}` inferred as both \
                             `{:?}` and `{:?}` from call site",
                            name, prior, bound
                        )));
                    }
                } else {
                    bindings.insert(name.clone(), bound);
                }
                return Ok(());
            }
        }
        // Otherwise structural recurse where shapes match.
        match (declared, actual) {
            (TypeExpr::Array { elem, .. }, CodegenTy::Array(a_elem, _)) => {
                Self::unify_generic_param_bindings(
                    elem, a_elem, params, bindings,
                )
            }
            (TypeExpr::Tuple(parts, _), CodegenTy::Tuple(a_parts))
                if parts.len() == a_parts.len() =>
            {
                for (p, a) in parts.iter().zip(a_parts) {
                    Self::unify_generic_param_bindings(
                        p, a, params, bindings,
                    )?;
                }
                Ok(())
            }
            // Concrete-vs-concrete shapes: nothing to bind.
            // Mismatches don't error here — the typechecker (or
            // the call site type check after substitution) will
            // surface them.
            _ => Ok(()),
        }
    }

    /// m62: infer the concrete type-args tuple for a generic fn
    /// call by unifying each declared param TypeExpr against the
    /// actual arg CodegenTy. Returns the args in the same order
    /// as the template's `generics: Vec<GenericParam>`.
    fn infer_generic_fn_args(
        template: &FnDecl,
        actual_arg_tys: &[CodegenTy],
    ) -> Result<Vec<TypeExpr>, CodegenError> {
        let visible_args = template.params.len().min(actual_arg_tys.len());
        let generic_param_names: BTreeSet<String> = template
            .generics
            .iter()
            .map(|g| g.name.name.clone())
            .collect();
        let mut bindings: BTreeMap<String, TypeExpr> = BTreeMap::new();
        for (p, actual_ty) in template
            .params
            .iter()
            .zip(actual_arg_tys.iter())
            .take(visible_args)
        {
            Self::unify_generic_param_bindings(
                &p.ty,
                actual_ty,
                &generic_param_names,
                &mut bindings,
            )?;
        }
        let mut args: Vec<TypeExpr> = Vec::new();
        for gp in &template.generics {
            match bindings.get(&gp.name.name) {
                Some(t) => args.push(t.clone()),
                None => {
                    return Err(CodegenError::Unsupported(format!(
                        "generic fn `{}`: could not infer param `{}` \
                         from call site (m62 v0.1 requires every \
                         generic param to appear in an arg position \
                         that pins it)",
                        template.name.name, gp.name.name
                    )));
                }
            }
        }
        Ok(args)
    }

    /// m62: synthesize a concrete (non-generic) FnDecl from a
    /// generic template + a tuple of resolved type args. The
    /// template's params, return type, and body type-ascriptions
    /// (let / let-tuple) are walked through `substitute_type_expr`.
    /// Body expression-level generic-typed sites that aren't
    /// covered (e.g., struct literals using a generic type
    /// without a let ascription) flow through as-is and rely on
    /// the m61b/m61c surface resolution at lowering time.
    fn synthesize_generic_fn_instantiation(
        template: &FnDecl,
        type_args: &[TypeExpr],
        mangled_name: &str,
    ) -> Result<FnDecl, CodegenError> {
        if template.generics.len() != type_args.len() {
            return Err(CodegenError::Unsupported(format!(
                "generic fn `{}`: expected {} type args, got {}",
                template.name.name,
                template.generics.len(),
                type_args.len()
            )));
        }
        Self::check_generic_bounds(
            "generic fn",
            &template.name.name,
            &template.generics,
            type_args,
        )?;
        let mut subst: BTreeMap<String, TypeExpr> = BTreeMap::new();
        for (gp, arg) in template.generics.iter().zip(type_args.iter()) {
            subst.insert(gp.name.name.clone(), arg.clone());
        }
        let new_params: Vec<Param> = template
            .params
            .iter()
            .map(|p| Param {
                name: p.name.clone(),
                ty: Self::substitute_type_expr(&p.ty, &subst),
                default: p.default.clone(),
                span: p.span.clone(),
            })
            .collect();
        let new_ret = template
            .ret
            .as_ref()
            .map(|t| Self::substitute_type_expr(t, &subst));
        let new_body = Self::substitute_block_type_ascriptions(
            &template.body,
            &subst,
        );
        let new_fallible = template
            .fallible
            .as_ref()
            .map(|t| Self::substitute_type_expr(t, &subst));
        Ok(FnDecl {
            name: Ident {
                name: mangled_name.to_string(),
                span: template.name.span.clone(),
            },
            generics: Vec::new(),
            params: new_params,
            ret: new_ret,
            fallible: new_fallible,
            // Monomorphized fns inherit the template's @ffi
            // annotation; @ffi + generics is rejected at parse
            // time so in practice this is always None here.
            ffi: template.ffi.clone(),
            export: template.export,
            unbounded: template.unbounded,
            body: new_body,
            span: template.span.clone(),
        })
    }

    /// m62: shallow walk of a block to substitute generic-param
    /// refs in any let/let-tuple type ascriptions. Other
    /// type-position uses inside the body (cast targets, nested
    /// fn decl signatures, etc.) are not walked — generic fn
    /// bodies that need those aren't expected at v0.1 and would
    /// surface as type errors after substitution leaves them
    /// pointing at unbound names.
    fn substitute_block_type_ascriptions(
        block: &Block,
        subst: &BTreeMap<String, TypeExpr>,
    ) -> Block {
        let new_stmts = block
            .stmts
            .iter()
            .map(|s| Self::substitute_stmt_type_ascriptions(s, subst))
            .collect();
        Block {
            stmts: new_stmts,
            tail: block.tail.clone(),
            span: block.span.clone(),
        }
    }

    fn substitute_stmt_type_ascriptions(
        stmt: &Stmt,
        subst: &BTreeMap<String, TypeExpr>,
    ) -> Stmt {
        match stmt {
            Stmt::Let { is_mut, name, ty, value, span } => Stmt::Let {
                is_mut: *is_mut,
                name: name.clone(),
                ty: ty
                    .as_ref()
                    .map(|t| Self::substitute_type_expr(t, subst)),
                value: value.clone(),
                span: span.clone(),
            },
            Stmt::LetTuple { is_mut, names, ty, value, span } => {
                Stmt::LetTuple {
                    is_mut: *is_mut,
                    names: names.clone(),
                    ty: ty
                        .as_ref()
                        .map(|t| Self::substitute_type_expr(t, subst)),
                    value: value.clone(),
                    span: span.clone(),
                }
            }
            other => other.clone(),
        }
    }



    /// m61b: comprehensive walk for generic instantiations
    /// across the entire program. Calls `collect_generic_uses` at
    /// every TypeExpr-bearing site we care about: type decl
    /// fields, fn / locus signatures, bus payload types, let
    /// ascriptions in fn bodies. The walk is purely structural —
    /// the typechecker has already validated names — and runs
    /// before any synthesis so the synthesized instantiations
    /// land in user_types before any concrete decl's bodies are
    /// resolved.
    fn collect_generic_uses_in_program(
        program: &Program,
        generic_names: &BTreeSet<String>,
        seen: &mut BTreeSet<String>,
        requests: &mut Vec<(String, Vec<TypeExpr>)>,
    ) -> Result<(), CodegenError> {
        for item in &program.items {
            match item {
                TopDecl::Type(t) if t.generics.is_empty() => {
                    match &t.body {
                        TypeDeclBody::Struct(fields) => {
                            for f in fields {
                                Self::collect_generic_uses(
                                    &f.ty,
                                    generic_names,
                                    seen,
                                    requests,
                                )?;
                            }
                        }
                        // m61c: enum variant field types can
                        // reference generic instantiations
                        // (e.g., a non-generic enum variant
                        // carrying a Box<Int> payload).
                        TypeDeclBody::Enum(variants) => {
                            for v in variants {
                                for f in &v.fields {
                                    Self::collect_generic_uses(
                                        f,
                                        generic_names,
                                        seen,
                                        requests,
                                    )?;
                                }
                            }
                        }
                        TypeDeclBody::Alias(_) => {}
                    }
                }
                TopDecl::Type(_) => {
                    /* generic template — its own body's `T`
                     * references aren't instantiations. */
                }
                TopDecl::Fn(f) => {
                    Self::collect_in_fn_decl(
                        f,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
                TopDecl::Locus(l) if l.generics.is_empty() => {
                    for member in &l.members {
                        Self::collect_in_locus_member(
                            member,
                            generic_names,
                            seen,
                            requests,
                        )?;
                    }
                }
                TopDecl::Locus(_) => {
                    /* m63: generic locus template — its members'
                     * type positions still mention the generic
                     * params (e.g. `Box<T>`) which can't unify
                     * against any actual concrete type yet.
                     * Synthesis later walks the substituted
                     * version. */
                }
                TopDecl::Const(c) => {
                    Self::collect_generic_uses(
                        &c.ty,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
                TopDecl::Perspective(_) | TopDecl::Module(_) => {
                    /* Perspective / Module type-bearing positions
                     * could grow into this when those features
                     * land in v0.1 codegen. */
                }
                TopDecl::Interface(_) => {
                    /* Interface declarations have no body to walk
                     * for generic uses. Method signatures are
                     * captured separately during the impl-check
                     * pass. */
                }
                TopDecl::Topic(t) => {
                    /* The topic's payload type may mention a
                     * generic name. Capture it the same way
                     * other type-bearing positions do. */
                    Self::collect_generic_uses(
                        &t.payload,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
                TopDecl::Target(_) => {
                    // FUv0.8.2 #7: target capability blocks
                    // carry no type-bearing positions; nothing
                    // to collect for generic monomorph.
                }
                TopDecl::RingLayout(_) => {
                    // ring_layout members are layout tokens, not
                    // type-bearing positions; nothing to collect.
                }
            }
        }
        Ok(())
    }

    fn collect_in_fn_decl(
        f: &FnDecl,
        generic_names: &BTreeSet<String>,
        seen: &mut BTreeSet<String>,
        requests: &mut Vec<(String, Vec<TypeExpr>)>,
    ) -> Result<(), CodegenError> {
        for p in &f.params {
            Self::collect_generic_uses(&p.ty, generic_names, seen, requests)?;
        }
        if let Some(ret) = &f.ret {
            Self::collect_generic_uses(ret, generic_names, seen, requests)?;
        }
        Self::collect_in_block(&f.body, generic_names, seen, requests)?;
        Ok(())
    }

    fn collect_in_locus_member(
        member: &LocusMember,
        generic_names: &BTreeSet<String>,
        seen: &mut BTreeSet<String>,
        requests: &mut Vec<(String, Vec<TypeExpr>)>,
    ) -> Result<(), CodegenError> {
        match member {
            LocusMember::Params(pb) => {
                for p in &pb.params {
                    if let Some(t) = &p.ty {
                        Self::collect_generic_uses(
                            t,
                            generic_names,
                            seen,
                            requests,
                        )?;
                    }
                }
            }
            LocusMember::Bus(bb) => {
                for bm in &bb.members {
                    match bm {
                        BusMember::Subscribe { ty: Some(t), .. } => {
                            Self::collect_generic_uses(
                                t,
                                generic_names,
                                seen,
                                requests,
                            )?;
                        }
                        BusMember::Publish { ty: Some(t), .. } => {
                            Self::collect_generic_uses(
                                t,
                                generic_names,
                                seen,
                                requests,
                            )?;
                        }
                        BusMember::Subscribe { ty: None, .. }
                        | BusMember::Publish { ty: None, .. } => {}
                    }
                }
            }
            LocusMember::Lifecycle(lc) => {
                for p in &lc.params {
                    Self::collect_generic_uses(
                        &p.ty,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
                if let Some(r) = &lc.ret {
                    Self::collect_generic_uses(
                        r,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
                Self::collect_in_block(
                    &lc.body,
                    generic_names,
                    seen,
                    requests,
                )?;
            }
            LocusMember::Fn(fd) => {
                Self::collect_in_fn_decl(
                    fd,
                    generic_names,
                    seen,
                    requests,
                )?;
            }
            LocusMember::Mode(_) => {
                /* Modes' body / params walk would mirror Fn; not
                 * yet wired. m61c. */
            }
            LocusMember::Const(c) => {
                Self::collect_generic_uses(
                    &c.ty,
                    generic_names,
                    seen,
                    requests,
                )?;
            }
            LocusMember::Type(t) if t.generics.is_empty() => {
                match &t.body {
                    TypeDeclBody::Struct(fields) => {
                        for f in fields {
                            Self::collect_generic_uses(
                                &f.ty,
                                generic_names,
                                seen,
                                requests,
                            )?;
                        }
                    }
                    TypeDeclBody::Enum(variants) => {
                        for v in variants {
                            for f in &v.fields {
                                Self::collect_generic_uses(
                                    f,
                                    generic_names,
                                    seen,
                                    requests,
                                )?;
                            }
                        }
                    }
                    TypeDeclBody::Alias(_) => {}
                }
            }
            LocusMember::Contract(_)
            | LocusMember::Failure(_)
            | LocusMember::Closure(_)
            | LocusMember::Type(_)
            | LocusMember::Bindings(_)
            | LocusMember::Placement(_)
            | LocusMember::BirthCheck(_) => {}
            LocusMember::Capacity(_) => {
                // F.22 slot cell types are concrete in v1; no
                // generic-template use sites. Future generic Pool/
                // Heap (`pool entries of T;` with locus generic
                // T) would walk slot.elem_ty here.
            }
        }
        Ok(())
    }

    fn collect_in_block(
        block: &Block,
        generic_names: &BTreeSet<String>,
        seen: &mut BTreeSet<String>,
        requests: &mut Vec<(String, Vec<TypeExpr>)>,
    ) -> Result<(), CodegenError> {
        for stmt in &block.stmts {
            Self::collect_in_stmt(stmt, generic_names, seen, requests)?;
        }
        Ok(())
    }

    fn collect_in_stmt(
        stmt: &Stmt,
        generic_names: &BTreeSet<String>,
        seen: &mut BTreeSet<String>,
        requests: &mut Vec<(String, Vec<TypeExpr>)>,
    ) -> Result<(), CodegenError> {
        match stmt {
            Stmt::Let { ty: Some(t), .. } => {
                Self::collect_generic_uses(t, generic_names, seen, requests)?;
            }
            Stmt::LetTuple { ty: Some(t), .. } => {
                Self::collect_generic_uses(t, generic_names, seen, requests)?;
            }
            _ => {}
        }
        Ok(())
    }

    /// m61: walk a TypeExpr looking for generic instantiations
    /// that reference one of the known generic templates. Each
    /// unique (template_name, args) tuple is recorded in
    /// `requests` (deduped via the mangled name in `seen`), with
    /// recursion into the args themselves so nested generics like
    /// `Box<Pair<Int, String>>` register `Pair_Int_String` first
    /// then `Box_Pair_Int_String`. Discovery is purely structural
    /// — the typechecker has already validated names.
    fn collect_generic_uses(
        t: &TypeExpr,
        generic_names: &BTreeSet<String>,
        seen: &mut BTreeSet<String>,
        requests: &mut Vec<(String, Vec<TypeExpr>)>,
    ) -> Result<(), CodegenError> {
        match t {
            TypeExpr::Named { path, generic_args, .. }
                if path.segments.len() == 1
                    && !generic_args.is_empty()
                    && generic_names
                        .contains(&path.segments[0].name) =>
            {
                // Recurse into args first so nested instantiations
                // are discovered (and end up in requests order
                // before the outer one — which is what
                // declare_user_type needs to resolve them).
                for a in generic_args {
                    Self::collect_generic_uses(
                        a,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
                let mangled = Self::mangle_generic_name(
                    &path.segments[0].name,
                    generic_args,
                )?;
                if seen.insert(mangled) {
                    requests.push((
                        path.segments[0].name.clone(),
                        generic_args.clone(),
                    ));
                }
            }
            TypeExpr::Named { generic_args, .. } => {
                /* non-generic Named ref (or unknown): still
                 * recurse into any args in case they themselves
                 * use a known generic template. */
                for a in generic_args {
                    Self::collect_generic_uses(
                        a,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
            }
            TypeExpr::Bounded { elem, .. } => Self::collect_generic_uses(
                elem,
                generic_names,
                seen,
                requests,
            )?,
            TypeExpr::Array { elem, .. } => Self::collect_generic_uses(
                elem,
                generic_names,
                seen,
                requests,
            )?,
            TypeExpr::Tuple(parts, _) => {
                for p in parts {
                    Self::collect_generic_uses(
                        p,
                        generic_names,
                        seen,
                        requests,
                    )?;
                }
            }
            TypeExpr::Projection { inner, .. } => Self::collect_generic_uses(
                inner,
                generic_names,
                seen,
                requests,
            )?,
            TypeExpr::Primitive(_, _) | TypeExpr::Function { .. } => {}
        }
        Ok(())
    }

    /// m61: synthesize a concrete TypeDecl from a generic template
    /// + a tuple of concrete type args. The synthesized decl has
    /// the mangled name (e.g., `Box_Int`), no generics, and a body
    /// where every reference to a generic param is substituted
    /// with the corresponding arg. Caller hands the result to
    /// `declare_user_type` like any other non-generic decl.
    fn synthesize_generic_instantiation(
        template: &TypeDecl,
        args: &[TypeExpr],
    ) -> Result<TypeDecl, CodegenError> {
        if template.generics.len() != args.len() {
            return Err(CodegenError::Unsupported(format!(
                "generic type `{}` expects {} args, got {}",
                template.name.name,
                template.generics.len(),
                args.len()
            )));
        }
        // m64: enforce declared bounds (e.g., `T: Numeric`)
        // before substitution.
        Self::check_generic_bounds(
            "generic type",
            &template.name.name,
            &template.generics,
            args,
        )?;
        let mangled = Self::mangle_generic_name(&template.name.name, args)?;

        let mut subst: BTreeMap<String, TypeExpr> = BTreeMap::new();
        for (gp, arg) in template.generics.iter().zip(args.iter()) {
            subst.insert(gp.name.name.clone(), arg.clone());
        }

        // Walk the body, substituting generic param refs.
        let new_body = match &template.body {
            TypeDeclBody::Struct(fields) => {
                let new_fields: Vec<StructField> = fields
                    .iter()
                    .map(|f| StructField {
                        name: f.name.clone(),
                        ty: Self::substitute_type_expr(&f.ty, &subst),
                        default: f.default.clone(),
                        tag: f.tag.clone(),
                        span: f.span.clone(),
                    })
                    .collect();
                TypeDeclBody::Struct(new_fields)
            }
            TypeDeclBody::Alias(_) => {
                return Err(CodegenError::Unsupported(format!(
                    "generic alias `{}` (m61c v0.1 supports struct \
                     and enum templates only)",
                    template.name.name
                )));
            }
            TypeDeclBody::Enum(variants) => {
                // m61c: substitute generic params throughout each
                // variant's field TypeExprs. Variant names stay as
                // declared (e.g., `Result_Int_String::Ok` keeps
                // `Ok` as the variant name) — the enum's mangled
                // outer name + variant lookup by string handles
                // namespacing.
                let new_variants: Vec<EnumVariant> = variants
                    .iter()
                    .map(|v| EnumVariant {
                        name: v.name.clone(),
                        fields: v
                            .fields
                            .iter()
                            .map(|f| {
                                Self::substitute_type_expr(f, &subst)
                            })
                            .collect(),
                        span: v.span.clone(),
                    })
                    .collect();
                TypeDeclBody::Enum(new_variants)
            }
        };

        Ok(TypeDecl {
            name: Ident {
                name: mangled,
                span: template.name.span.clone(),
            },
            generics: Vec::new(),
            body: new_body,
            span: template.span.clone(),
        })
    }





    /// Open-question #24 v0.2 epilogue. Branch on `path_alloca`.
    /// On the ok path, load `ret_alloca` and (for heap-bearing
    /// success types) deep-copy through `emit_method_return_deep_copy`
    /// into the TLS-snapshot'd caller_arena, then store into
    /// `out_val`. On the fail path, same shape with
    /// `err_alloca` → `out_err`. Both branches converge on a
    /// cleanup block that destroys the per-call scratch (set
    /// up in `lower_fallible_locus_method_body` via
    /// `open_method_scratch`), flushes the dissolve frame, and
    /// `ret i1 path`.
    ///
    /// `emit_method_return_deep_copy` no-ops for scalar / view
    /// / Cell types (`ty_needs_self_field_deep_copy` returns
    /// false) — the value passes through unchanged and the
    /// sret store writes its bytes directly. So this epilogue
    /// works the same as the v0.1 value-only epilogue did for
    /// flat payloads; the heap-bearing case is the new path.
    #[allow(clippy::too_many_arguments)]

    /// Declare a user-defined fn's LLVM function value and signature.
    /// Body lowering happens in a separate pass so calls in pass 2
    /// can resolve to fns declared anywhere in the program.
    fn declare_user_fn(&mut self, f: &FnDecl) -> Result<(), CodegenError> {
        if !f.generics.is_empty() {
            // m62: generic templates declare nothing directly.
            // Per-instantiation specialized fns get declared
            // on-demand from `lower_call_expr` once arg types
            // are known and inference can pin the type args.
            return Ok(());
        }
        // Stage-1 FFI (2026-05-22): @ffi("c") declarations get a
        // separate signature build — no implicit __caller_arena
        // prefix, no fallible sret slots, no Hale-internal type
        // wrapping. The LLVM function is `add_function`-emitted
        // with the literal Hale fn name as the C symbol; with
        // no body emitted later (lower_user_fn_body skips for
        // ffi), LLVM treats this as `declare` and the linker
        // resolves at link time against the .c file the library
        // author shipped.
        if f.ffi.is_some() {
            return self.declare_ffi_fn(f);
        }
        let mut param_tys = Vec::with_capacity(f.params.len());
        let ptr_t_for_caller_arena =
            self.context.ptr_type(AddressSpace::default());
        let mut llvm_param_tys: Vec<inkwell::types::BasicMetadataTypeEnum> =
            Vec::with_capacity(f.params.len() + 1);
        // m49: implicit `__caller_arena: ptr` first param. Caller
        // passes their `current_arena_ptr()`; callee opens a
        // subregion of it at body entry. `params` / `defaults` /
        // user-visible arity stays unchanged — this is purely an
        // ABI-level implicit prefix.
        llvm_param_tys.push(ptr_t_for_caller_arena.into());
        let mut defaults: Vec<Option<Expr>> = Vec::with_capacity(f.params.len());
        let mut seen_default = false;
        for p in &f.params {
            if p.default.is_some() {
                seen_default = true;
            } else if seen_default {
                // Suffix-only rule: a non-defaulted param can't
                // follow a defaulted one. Otherwise the
                // omit-trailing-args ABI breaks down — the caller
                // can't tell which positional slot they're filling.
                return Err(CodegenError::Unsupported(format!(
                    "fn `{}`: required param `{}` follows a defaulted \
                     param; defaults must form a suffix",
                    f.name.name, p.name.name
                )));
            }
            let lt = self.type_expr_to_codegen_ty(&p.ty)?;
            llvm_param_tys.push(self.llvm_basic_type(&lt).into());
            param_tys.push(lt);
            defaults.push(p.default.clone());
        }
        // A2 (G2): treat `-> ()` (parsed as an empty tuple) as
        // Unit, equivalent to omitting the return type. The downstream
        // ABI shape — both for the non-fallible and the fallible
        // path — is keyed off `Option<CodegenTy>` ret, where `None`
        // means Unit. Without this rewrite, `type_expr_to_codegen_ty`
        // rejects the empty tuple at line ~5439.
        let ret_te_normalized: Option<&TypeExpr> = match &f.ret {
            Some(TypeExpr::Tuple(parts, _)) if parts.is_empty() => None,
            other => other.as_ref(),
        };
        let ret_ty = match ret_te_normalized {
            Some(t) => Some(self.type_expr_to_codegen_ty(t)?),
            None => None,
        };

        // v1.x-FORM-2 PR6: fallible(E) lowering. The Hale-level
        // return type T becomes an `T*` sret param; payload type E
        // becomes a second `E*` sret param. The LLVM-level return
        // becomes `i1` (true = err path, false = ok). Caller
        // allocates both slots and branches on the i1; see
        // commit-3 call-site plumbing.
        //
        // A2 (G2): `-> () fallible(E)` (Unit success) skips the
        // out_val sret slot — only out_err is plumbed through.
        // emit_fallible_fn_exit_epilogue's ok-branch already guards
        // on `(sig.ret, out_val_param)` so a None ret + None
        // out_val_param falls through to cleanup without a copy.
        let fallible_payload_ty: Option<CodegenTy> =
            match (&f.fallible, &ret_ty) {
                (Some(payload_te), Some(_)) => {
                    let pt = self.type_expr_to_codegen_ty(payload_te)?;
                    let ptr_t = self.context.ptr_type(AddressSpace::default());
                    // out_val sret slot.
                    llvm_param_tys.push(ptr_t.into());
                    // out_err sret slot.
                    llvm_param_tys.push(ptr_t.into());
                    Some(pt)
                }
                (Some(payload_te), None) => {
                    let pt = self.type_expr_to_codegen_ty(payload_te)?;
                    let ptr_t = self.context.ptr_type(AddressSpace::default());
                    // Unit success: only the out_err sret slot.
                    llvm_param_tys.push(ptr_t.into());
                    Some(pt)
                }
                (None, _) => None,
            };

        let fn_ty = if fallible_payload_ty.is_some() {
            self.context.bool_type().fn_type(&llvm_param_tys, false)
        } else {
            match &ret_ty {
                Some(CodegenTy::Bounded(_, _)) => {
                    return Err(CodegenError::Unsupported(
                        "bounded[T; N] cannot be returned by value — it \
                         lives inline in its containing type"
                            .into(),
                    ));
                }
                Some(CodegenTy::Int) | Some(CodegenTy::Duration) => self
                    .context
                    .i64_type()
                    .fn_type(&llvm_param_tys, false),
                Some(CodegenTy::Float) => {
                    self.context.f64_type().fn_type(&llvm_param_tys, false)
                }
                Some(CodegenTy::Decimal) => {
                    self.context.i128_type().fn_type(&llvm_param_tys, false)
                }
                Some(CodegenTy::Bool) => {
                    self.context.bool_type().fn_type(&llvm_param_tys, false)
                }
                Some(CodegenTy::Enum(name)) => {
                    if self
                        .user_enums
                        .get(name.as_str())
                        .map(|i| i.has_payload)
                        .unwrap_or(false)
                    {
                        self.context
                            .ptr_type(AddressSpace::default())
                            .fn_type(&llvm_param_tys, false)
                    } else {
                        self.context.i32_type().fn_type(&llvm_param_tys, false)
                    }
                }
                Some(CodegenTy::BytesView) | Some(CodegenTy::StringView) | Some(CodegenTy::BytesMut) => self
                    .view_struct_ty()
                    .fn_type(&llvm_param_tys, false),
                Some(CodegenTy::String)
                | Some(CodegenTy::Bytes)
                | Some(CodegenTy::Time)
                | Some(CodegenTy::LocusRef(_))
                | Some(CodegenTy::TypeRef(_))
                | Some(CodegenTy::Array(_, _))
                | Some(CodegenTy::Tuple(_))
                | Some(CodegenTy::FnPtr { .. })
                | Some(CodegenTy::Interface(_))
                | Some(CodegenTy::Cell(_, _))
                | Some(CodegenTy::Drain(_)) => self
                    .context
                    .ptr_type(AddressSpace::default())
                    .fn_type(&llvm_param_tys, false),
                None => self
                    .context
                    .void_type()
                    .fn_type(&llvm_param_tys, false),
            }
        };
        // WASM entry-inversion: an `@export` fn's real (arena-ABI)
        // implementation takes an internal symbol; the literal name is
        // claimed by the arena-less export wrapper emitted later
        // (synthesize_wasm_export_wrappers). Internal Hale callers
        // resolve through `user_fns[name].func` (the SSA value), so the
        // symbol rename is invisible to them. Native builds keep the
        // literal name (no wrapper, `@export` is a no-op).
        let impl_symbol = if self.is_wasm && f.export {
            format!("__hale_impl_{}", f.name.name)
        } else {
            f.name.name.clone()
        };
        let func = self.module.add_function(&impl_symbol, fn_ty, None);
        // 2026-07-01 aliasing metadata, stage 1: the implicit
        // `__caller_arena` (param 0) is `noalias` — the arena STRUCT
        // and its metadata are reachable only through this pointer
        // within the call (user-visible values point into chunk DATA
        // bytes, which bump allocation never re-hands out, so actual
        // accessed locations never overlap). Hale code never unwinds
        // (failure is fallible-sret or violate→process-exit), so
        // every user fn is `nounwind`.
        {
            use inkwell::attributes::{Attribute, AttributeLoc};
            let noalias_kind = Attribute::get_named_enum_kind_id("noalias");
            let nounwind_kind = Attribute::get_named_enum_kind_id("nounwind");
            func.add_attribute(
                AttributeLoc::Param(0),
                self.context.create_enum_attribute(noalias_kind, 0),
            );
            func.add_attribute(
                AttributeLoc::Function,
                self.context.create_enum_attribute(nounwind_kind, 0),
            );
        }
        // FORM-3: skip the per-call scratch arena when the body provably
        // allocates nothing. The decision is the call-graph fixpoint
        // (`compute_nonalloc_free_fns`, run at lower_program start into
        // `self.nonalloc_free_fns`): it's type-aware (Int/Float/Duration `+`
        // is arithmetic, not String concat) AND interprocedural (calls to
        // other proven-non-allocating fns don't allocate). Fallible fns are
        // excluded there (the `fail E` path arena-allocs a payload).
        let non_allocating = self.nonalloc_free_fns.contains(&f.name.name);
        self.user_fns.insert(
            f.name.name.clone(),
            FnSig {
                func,
                params: param_tys,
                defaults,
                ret: ret_ty,
                fallible: fallible_payload_ty,
                non_allocating,
                is_ffi: false,
                ffi_js: false,
            },
        );
        Ok(())
    }

    /// WASM entry-inversion (2026-06-16). Emit:
    ///   * `_hale_start()` — a once-at-load setup entry that creates the
    ///     PERSISTENT program arena + bus queue and stores them in the
    ///     usual globals. Unlike `main`, nothing is torn down, so values
    ///     an export allocates (or parks via the runtime state cell) live
    ///     for the module's lifetime. The JS loader calls it before any
    ///     export, and (in entry-inversion mode) does NOT call `main` —
    ///     so `main`'s own create+destroy of the arena can't clobber it.
    ///   * one arena-less wrapper per `@export fn`, under the literal fn
    ///     name, that loads that persistent arena and tail-calls the real
    ///     implementation (`__hale_impl_<name>`, arena-ABI). The JS host
    ///     calls these with just the declared args.
    /// Collected names are handed to `wasm-ld --export=`.
    fn synthesize_wasm_export_wrappers(
        &mut self,
        user_fn_decls: &[FnDecl],
    ) -> Result<(), CodegenError> {
        let has_export_fn = user_fn_decls.iter().any(|f| f.export);
        // The persistent singleton: `@export locus L { ... }` (at most one).
        let export_locus_name: Option<String> = self
            .program
            .items
            .iter()
            .find_map(|it| match it {
                TopDecl::Locus(l) if l.export => Some(l.name.name.clone()),
                _ => None,
            });
        if !has_export_fn && export_locus_name.is_none() {
            return Ok(());
        }
        let ptr_t = self.context.ptr_type(AddressSpace::default());
        let void_t = self.context.void_type();
        let emit = |s: &str| CodegenError::LlvmEmit(s.to_string());

        // ---- _hale_start(): persistent arena + bus queue -------------
        let start_fn =
            self.module
                .add_function("_hale_start", void_t.fn_type(&[], false), None);
        let entry = self.context.append_basic_block(start_fn, "entry");
        self.builder.position_at_end(entry);
        let arena_create = self
            .module
            .get_function("lotus_arena_create_labeled")
            .expect("lotus_arena_create_labeled declared");
        let label = self
            .builder
            .build_global_string_ptr("lotus.arena.global", "hale_start.arena.label")
            .map_err(|e| emit(&e.to_string()))?
            .as_pointer_value();
        let arena_ptr = self
            .builder
            .build_call(arena_create, &[label.into()], "hale_start.arena")
            .map_err(|e| emit(&e.to_string()))?
            .try_as_basic_value()
            .left()
            .expect("arena ptr");
        let arena_global = self
            .module
            .get_global("lotus.arena.global")
            .expect("arena global declared");
        self.builder
            .build_store(arena_global.as_pointer_value(), arena_ptr)
            .map_err(|e| emit(&e.to_string()))?;
        let q_create = self
            .module
            .get_function("lotus_bus_queue_create")
            .expect("lotus_bus_queue_create declared");
        let q_ptr = self
            .builder
            .build_call(q_create, &[], "hale_start.queue")
            .map_err(|e| emit(&e.to_string()))?
            .try_as_basic_value()
            .left()
            .expect("queue ptr");
        let q_global = self
            .module
            .get_global("lotus.bus_queue.global")
            .expect("bus queue global declared");
        self.builder
            .build_store(q_global.as_pointer_value(), q_ptr)
            .map_err(|e| emit(&e.to_string()))?;
        let set_q = self
            .module
            .get_function("lotus_bus_set_queue")
            .expect("lotus_bus_set_queue declared");
        self.builder
            .build_call(set_q, &[q_ptr.into()], "")
            .map_err(|e| emit(&e.to_string()))?;

        // Persistent singleton: instantiate the `@export locus` here.
        // birth() runs now; the dissolve is registered in a frame we
        // then DISCARD (pop, never flush) so it never fires — the app
        // lives for the module's lifetime. self-ptr → `@lotus.app.self`.
        if let Some(ref lname) = export_locus_name {
            if self
                .user_loci
                .get(lname)
                .map_or(false, |i| i.methods.contains_key("run"))
            {
                return Err(CodegenError::Unsupported(format!(
                    "@export locus `{}` must not define `run()` — a wasm \
                     singleton is host-driven via its `@export` methods, not \
                     a cooperative run loop",
                    lname
                )));
            }
            let app_self_global =
                self.module.add_global(ptr_t, None, "lotus.app.self");
            app_self_global.set_initializer(&ptr_t.const_null());
            app_self_global.set_linkage(inkwell::module::Linkage::Internal);
            self.current_fn = Some(start_fn);
            self.deferred_dissolves.push(Vec::new());
            self.defer_next_locus_dissolve = true;
            // Allocate the singleton in the persistent global arena, not
            // a stack alloca — it must outlive _hale_start.
            self.instantiating_persistent_singleton = true;
            let scope = Scope::default();
            let self_ptr = self.lower_locus_instantiation(lname, &[], &scope)?;
            self.instantiating_persistent_singleton = false;
            self.defer_next_locus_dissolve = false;
            // Drop the frame WITHOUT flushing → no dissolve IR emitted.
            let _ = self.deferred_dissolves.pop();
            self.builder
                .build_store(app_self_global.as_pointer_value(), self_ptr)
                .map_err(|e| emit(&e.to_string()))?;
            self.current_fn = None;
        }
        self.builder
            .build_return(None)
            .map_err(|e| emit(&e.to_string()))?;
        self.wasm_exports.push("_hale_start".to_string());

        // ---- one wrapper per @export fn ------------------------------
        for f in user_fn_decls {
            if !f.export {
                continue;
            }
            let name = &f.name.name;
            let sig = self
                .user_fns
                .get(name)
                .cloned()
                .expect("@export fn declared in pass B");
            if sig.fallible.is_some() {
                return Err(CodegenError::Unsupported(format!(
                    "@export fn `{}`: fallible exports are not supported \
                     yet (wasm entry-inversion v1)",
                    name
                )));
            }
            let mut wparam_tys: Vec<inkwell::types::BasicMetadataTypeEnum> =
                Vec::with_capacity(sig.params.len());
            for p in &sig.params {
                wparam_tys.push(self.llvm_basic_type(p).into());
            }
            let wrapper_ty = match &sig.ret {
                Some(rt) => self.llvm_basic_type(rt).fn_type(&wparam_tys, false),
                None => void_t.fn_type(&wparam_tys, false),
            };
            let wrapper = self.module.add_function(name, wrapper_ty, None);
            let wentry = self.context.append_basic_block(wrapper, "entry");
            self.builder.position_at_end(wentry);
            let arena_ld = self
                .builder
                .build_load(ptr_t, arena_global.as_pointer_value(), "export.arena")
                .map_err(|e| emit(&e.to_string()))?;
            let mut call_args: Vec<inkwell::values::BasicMetadataValueEnum> =
                Vec::with_capacity(sig.params.len() + 1);
            call_args.push(arena_ld.into());
            for i in 0..sig.params.len() {
                call_args.push(
                    wrapper
                        .get_nth_param(i as u32)
                        .expect("wrapper param")
                        .into(),
                );
            }
            let call = self
                .builder
                .build_call(sig.func, &call_args, "export.call")
                .map_err(|e| emit(&e.to_string()))?;
            match &sig.ret {
                Some(_) => {
                    let rv = call
                        .try_as_basic_value()
                        .left()
                        .expect("non-void export returns a value");
                    self.builder
                        .build_return(Some(&rv))
                        .map_err(|e| emit(&e.to_string()))?;
                }
                None => {
                    self.builder
                        .build_return(None)
                        .map_err(|e| emit(&e.to_string()))?;
                }
            }
            self.wasm_exports.push(name.clone());
        }

        // ---- export wrappers for the @export locus's methods ---------
        // Each non-fallible `fn` method becomes a wasm export under its
        // bare name: load the singleton self-ptr, call the method
        // (`[self_ptr, host args...]`), return the result. State lives in
        // the locus's fields, so it persists across these calls.
        if let Some(lname) = export_locus_name {
            let methods: Vec<(String, inkwell::values::FunctionValue<'ctx>)> = self
                .user_loci
                .get(&lname)
                .map(|i| {
                    i.user_methods.iter().map(|(k, v)| (k.clone(), *v)).collect()
                })
                .unwrap_or_default();
            // Methods declared `fallible(E)` can't be exported (v1 — the
            // host has no error channel); they stay internal.
            let fallible_methods: std::collections::BTreeSet<String> = self
                .program
                .items
                .iter()
                .find_map(|it| match it {
                    TopDecl::Locus(l) if l.name.name == lname => Some(
                        l.members
                            .iter()
                            .filter_map(|m| match m {
                                LocusMember::Fn(fd) if fd.fallible.is_some() => {
                                    Some(fd.name.name.clone())
                                }
                                _ => None,
                            })
                            .collect(),
                    ),
                    _ => None,
                })
                .unwrap_or_default();
            let app_self_global = self
                .module
                .get_global("lotus.app.self")
                .expect("app self global declared in _hale_start");
            for (mname, mfunc) in methods {
                if fallible_methods.contains(&mname) {
                    continue;
                }
                // Defensive: skip a bare-name collision with an existing
                // symbol (method symbols are `Locus.method`, so the bare
                // name is normally free).
                if self.module.get_function(&mname).is_some() {
                    continue;
                }
                let fnty = mfunc.get_type();
                let ptys = fnty.get_param_types(); // [self_ptr, args...]
                let wparams: Vec<inkwell::types::BasicMetadataTypeEnum> =
                    ptys.iter().skip(1).map(|t| (*t).into()).collect();
                let wrapper_ty = match fnty.get_return_type() {
                    Some(rt) => rt.fn_type(&wparams, false),
                    None => void_t.fn_type(&wparams, false),
                };
                let wrapper = self.module.add_function(&mname, wrapper_ty, None);
                let wentry = self.context.append_basic_block(wrapper, "entry");
                self.builder.position_at_end(wentry);
                let self_ld = self
                    .builder
                    .build_load(ptr_t, app_self_global.as_pointer_value(), "app.self")
                    .map_err(|e| emit(&e.to_string()))?;
                let mut args: Vec<inkwell::values::BasicMetadataValueEnum> =
                    Vec::with_capacity(wparams.len() + 1);
                args.push(self_ld.into());
                for i in 0..wparams.len() {
                    args.push(
                        wrapper.get_nth_param(i as u32).expect("wrapper param").into(),
                    );
                }
                let call = self
                    .builder
                    .build_call(mfunc, &args, "method.export.call")
                    .map_err(|e| emit(&e.to_string()))?;
                match fnty.get_return_type() {
                    Some(_) => {
                        let rv = call
                            .try_as_basic_value()
                            .left()
                            .expect("non-void method returns a value");
                        self.builder
                            .build_return(Some(&rv))
                            .map_err(|e| emit(&e.to_string()))?;
                    }
                    None => {
                        self.builder
                            .build_return(None)
                            .map_err(|e| emit(&e.to_string()))?;
                    }
                }
                self.wasm_exports.push(mname.clone());
            }
        }
        Ok(())
    }

    /// Stage-1 FFI (2026-05-22): declare an `@ffi("c")` fn at the
    /// LLVM level. The C-ABI signature is built from the Hale
    /// types per `spec/ffi.md`'s marshalling table — no implicit
    /// `__caller_arena` prefix, no fallible sret slots, no
    /// monomorphization. The LLVM symbol is the literal Hale fn
    /// name; the library author's `.c` glue exports a function
    /// with that same name, and the linker resolves at link time.
    /// No body IR is emitted (the parser synthesizes an empty
    /// `Block` for @ffi fns; `lower_user_fn_body` short-circuits).
    /// Result: LLVM emits `declare <ret> @<name>(<args>)` and the
    /// final link line picks up the implementation.
    fn declare_ffi_fn(&mut self, f: &FnDecl) -> Result<(), CodegenError> {
        // `@ffi("js")` host imports marshal i64-class scalars as f64
        // (JS `number`) instead of i64 (JS `BigInt`). `@ffi("c")`
        // keeps i64 — on wasm those resolve to linked runtime C
        // symbols that expect i64, not the JS boundary.
        let ffi_js = f
            .ffi
            .as_ref()
            .map(|a| a.abi == "js")
            .unwrap_or(false);
        let mut param_tys = Vec::with_capacity(f.params.len());
        let mut llvm_param_tys: Vec<inkwell::types::BasicMetadataTypeEnum> =
            Vec::with_capacity(f.params.len());
        let mut defaults: Vec<Option<Expr>> = Vec::with_capacity(f.params.len());
        for p in &f.params {
            if p.default.is_some() {
                return Err(CodegenError::Unsupported(format!(
                    "@ffi fn `{}`: parameter defaults are not supported \
                     across the C-ABI boundary (param `{}` has a default)",
                    f.name.name, p.name.name
                )));
            }
            let lt = self.type_expr_to_codegen_ty(&p.ty)?;
            let llvm_ty = self.llvm_ffi_param_type(&lt, ffi_js, &f.name.name, &p.name.name)?;
            llvm_param_tys.push(llvm_ty);
            param_tys.push(lt);
            defaults.push(None);
        }
        let ret_te_normalized: Option<&TypeExpr> = match &f.ret {
            Some(TypeExpr::Tuple(parts, _)) if parts.is_empty() => None,
            other => other.as_ref(),
        };
        let ret_ty: Option<CodegenTy> = match ret_te_normalized {
            Some(t) => Some(self.type_expr_to_codegen_ty(t)?),
            None => None,
        };
        // sret-style struct returns: when the Hale fn declares
        // `-> TypeRef(...)`, the LLVM signature gets a hidden ptr
        // param prepended (caller allocates the slot, callee
        // fills) and returns void. The Hale call site allocates
        // the slot in its arena and surfaces the pointer as the
        // expression's value — symmetric with how user-type
        // instantiations already work. C glue authors write
        //   `void foo(T *out, ...) { *out = ...; }`
        // matching the signature.
        let struct_return = matches!(&ret_ty, Some(CodegenTy::TypeRef(_)));
        if struct_return {
            let ptr_t = self.context.ptr_type(AddressSpace::default());
            // Prepend the sret slot pointer.
            llvm_param_tys.insert(0, ptr_t.into());
        }
        let fn_ty = if struct_return {
            // sret signature: void return, prepended ptr first arg.
            self.context
                .void_type()
                .fn_type(&llvm_param_tys, false)
        } else {
            match &ret_ty {
                Some(rt) => {
                    let llvm_ret =
                        self.llvm_ffi_return_type(rt, ffi_js, &f.name.name)?;
                    llvm_ret.fn_type(&llvm_param_tys, false)
                }
                None => self
                    .context
                    .void_type()
                    .fn_type(&llvm_param_tys, false),
            }
        };
        let func = self.module.add_function(&f.name.name, fn_ty, None);
        self.user_fns.insert(
            f.name.name.clone(),
            FnSig {
                func,
                params: param_tys,
                defaults,
                ret: ret_ty,
                fallible: None,
                non_allocating: true,
                is_ffi: true,
                ffi_js,
            },
        );
        Ok(())
    }

    /// FFI parameter-type lowering. Maps an Hale codegen type to
    /// the LLVM type used at the C-ABI boundary per `spec/ffi.md`.
    /// User-type structs (TypeRef) pass by value; the call-site
    /// loads the struct from its heap pointer and passes the
    /// value, and LLVM lowers struct-by-value per the platform
    /// ABI (SysV register-classification on x86_64, etc.).
    fn llvm_ffi_param_type(
        &self,
        ty: &CodegenTy,
        is_js: bool,
        fn_name: &str,
        param_name: &str,
    ) -> Result<inkwell::types::BasicMetadataTypeEnum<'ctx>, CodegenError> {
        let ptr_t = self.context.ptr_type(AddressSpace::default());
        match ty {
            CodegenTy::Bounded(_, _) => {
                return Err(CodegenError::Unsupported(format!(
                    "@ffi fn `{}` param `{}`: bounded[T; N] has no \
                     portable C mapping",
                    fn_name, param_name
                )));
            }
            // `@ffi("js")`: i64-class scalars cross as f64 (JS number),
            // not i64 (BigInt). The call site sitofp's before the call.
            CodegenTy::Int | CodegenTy::Duration if is_js => {
                Ok(self.context.f64_type().into())
            }
            CodegenTy::Int
            | CodegenTy::Duration
            | CodegenTy::Time => Ok(self.context.i64_type().into()),
            CodegenTy::Float => Ok(self.context.f64_type().into()),
            CodegenTy::Bool => Ok(self.context.i32_type().into()),
            CodegenTy::String | CodegenTy::Bytes => Ok(ptr_t.into()),
            CodegenTy::BytesView | CodegenTy::StringView | CodegenTy::BytesMut => {
                // 16-byte struct by value: { ptr, i64 }.
                Ok(self.view_struct_ty().into())
            }
            CodegenTy::TypeRef(name) => {
                // Stage 1 follow-on (2026-05-22): user-type struct
                // passed by POINTER, not by value. The Hale side
                // stores user structs as heap pointers already, so
                // the natural mapping is `ptr` at the C-ABI level.
                // The glue's C-side signature receives `const T *`
                // (or `T *` if it mutates); SysV's struct-by-value
                // classification rules are sidestepped entirely,
                // which makes the substrate portable across
                // x86_64-SysV / Win64 / aarch64 without per-platform
                // ABI-lowering passes. Library authors trade a
                // slightly more verbose glue (one dereference per
                // arg) for predictable codegen.
                //
                // Verify the type is declared so we surface a
                // useful diagnostic at declaration time, not at
                // link time when the symbol references go unresolved.
                self.user_types.get(name).ok_or_else(|| {
                    CodegenError::Unsupported(format!(
                        "@ffi fn `{}` parameter `{}`: user type `{}` \
                         is not declared in this program",
                        fn_name, param_name, name
                    ))
                })?;
                Ok(ptr_t.into())
            }
            CodegenTy::Tuple(_)
            | CodegenTy::Array(_, _)
            | CodegenTy::Interface(_)
            | CodegenTy::Enum(_)
            | CodegenTy::LocusRef(_)
            | CodegenTy::Cell(_, _)
            | CodegenTy::FnPtr { .. }
            | CodegenTy::Drain(_)
            | CodegenTy::Decimal => Err(CodegenError::Unsupported(format!(
                "@ffi fn `{}` parameter `{}`: type {:?} is not yet wired \
                 for FFI codegen at Stage 1. See spec/ffi.md.",
                fn_name, param_name, ty
            ))),
        }
    }

    /// FFI return-type lowering. Mirror of `llvm_ffi_param_type`
    /// for the return slot. User-type structs use sret-style: the
    /// caller allocates the return slot in its arena, passes a
    /// pointer to it as a SYNTHETIC FIRST ARG, and the LLVM-level
    /// fn returns void. The actual sret transformation happens in
    /// `declare_ffi_fn` (it sees TypeRef return → prepends the
    /// hidden ptr param and substitutes void); this helper returns
    /// the *abstract* user-facing return shape (`ptr`) so call
    /// sites can plumb the slot allocation symmetrically.
    fn llvm_ffi_return_type(
        &self,
        ty: &CodegenTy,
        is_js: bool,
        fn_name: &str,
    ) -> Result<inkwell::types::BasicTypeEnum<'ctx>, CodegenError> {
        let ptr_t = self.context.ptr_type(AddressSpace::default());
        match ty {
            // `@ffi("js")`: i64-class scalars return as f64 (JS number);
            // the call site fptosi's the result back to i64.
            CodegenTy::Int | CodegenTy::Duration if is_js => {
                Ok(self.context.f64_type().into())
            }
            CodegenTy::Int
            | CodegenTy::Duration
            | CodegenTy::Time => Ok(self.context.i64_type().into()),
            CodegenTy::Float => Ok(self.context.f64_type().into()),
            CodegenTy::Bool => Ok(self.context.i32_type().into()),
            CodegenTy::String | CodegenTy::Bytes => Ok(ptr_t.into()),
            CodegenTy::BytesView | CodegenTy::StringView | CodegenTy::BytesMut => {
                Ok(self.view_struct_ty().into())
            }
            CodegenTy::TypeRef(name) => {
                self.user_types.get(name).ok_or_else(|| {
                    CodegenError::Unsupported(format!(
                        "@ffi fn `{}` return type: user type `{}` is \
                         not declared in this program",
                        fn_name, name
                    ))
                })?;
                // sret slot pointer — caller allocates, callee
                // fills. See declare_ffi_fn for the signature
                // transformation that hides this from user code.
                Ok(ptr_t.into())
            }
            _ => Err(CodegenError::Unsupported(format!(
                "@ffi fn `{}` return type {:?} is not yet wired for \
                 FFI codegen at Stage 1. See spec/ffi.md.",
                fn_name, ty
            ))),
        }
    }

    /// Lower a user fn's body. Each declared param is materialized
    /// as an alloca in the entry block so reads through `Ident`
    /// see the value-stored slot exactly the way `let`-bindings do.
    ///
    /// m49: every non-main free fn has an implicit `__caller_arena:
    /// ptr` first param at the LLVM ABI. The body opens a subregion
    /// of that arena so its allocations route through a per-call
    /// region that gets wholesale-freed at fn return. Heap-typed
    /// return values are deep-copied into `__caller_arena` before
    /// the subregion is destroyed. All `return` statements branch
    /// to a unified `fn.exit` epilogue block to avoid duplicating
    /// the destroy + copy at every return site.
    fn lower_user_fn_body(&mut self, f: &FnDecl) -> Result<(), CodegenError> {
        if !f.generics.is_empty() {
            // m62: generic templates have no body to lower until
            // call sites pin the type args. lower_call_expr
            // synthesizes + lowers per-instantiation bodies on-
            // demand.
            return Ok(());
        }
        if f.ffi.is_some() {
            // Stage-1 FFI: @ffi fns have no Hale-side body to
            // lower. The LLVM declaration emitted by declare_ffi_fn
            // is sufficient; the linker resolves against the
            // library author's C glue at link time.
            return Ok(());
        }
        let sig = self
            .user_fns
            .get(&f.name.name)
            .cloned()
            .expect("fn declared in pass 1");
        let func = sig.func;
        let entry = self.context.append_basic_block(func, "entry");
        self.builder.position_at_end(entry);
        self.current_fn = Some(func);
        self.current_user_fn_ret = Some(sig.ret.clone());
        self.current_self = None;
        self.loops.clear();
        // Fn-call protocol shave: non-allocating bodies can't publish,
        // so their (empty-frame) scope-exit flushes skip the bus drain.
        let prev_skip_drain = self.current_fn_skip_exit_drain;
        self.current_fn_skip_exit_drain = sig.non_allocating;
        self.push_dissolve_frame();

        let ptr_t = self.context.ptr_type(AddressSpace::default());

        // m49: implicit __caller_arena param materializes into a
        // local alloca first, before any user code runs. The
        // alloca is what the deep-copy epilogue reads back —
        // reading the LLVM param directly would also work since
        // params are SSA values that live for the whole fn, but
        // going through an alloca keeps the IR shape uniform with
        // every other binding the body sees.
        let caller_arena_alloca = self
            .builder
            .build_alloca(ptr_t, "__caller_arena.slot")
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        let caller_arena_param = func
            .get_nth_param(0)
            .expect("implicit __caller_arena param at slot 0");
        self.builder
            .build_store(caller_arena_alloca, caller_arena_param)
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;

        // FORM-3 (2026-05-13): subregion elision for non-allocating
        // bodies. When the classifier proved the body doesn't touch
        // the arena allocator, the subregion is dead weight — we
        // never alloc into it and never need to deep-copy a return
        // value out of it. Wire fn_arena_alloca = caller_arena_alloca
        // so any incidental `current_arena_ptr` reads route to the
        // caller's arena (a no-op in practice since the classifier
        // guarantees there are no such reads), and skip the
        // create/destroy lifecycle.
        //
        // m49 default (when allocating): open a subregion of
        // caller_arena. The body's allocations route through this.
        // The fn_arena_alloca survives across blocks via the
        // alloca + load pattern.
        let fn_arena_alloca = if sig.non_allocating {
            caller_arena_alloca
        } else {
            let subregion_create = self
                .module
                .get_function("lotus_arena_create_subregion")
                .expect("lotus_arena_create_subregion declared");
            let fn_arena_ptr = self
                .builder
                .build_call(
                    subregion_create,
                    &[caller_arena_param.into()],
                    "fn.arena.create",
                )
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?
                .try_as_basic_value()
                .left()
                .expect("subregion_create returns ptr");
            let alloca = self
                .builder
                .build_alloca(ptr_t, "fn.arena.slot")
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            self.builder
                .build_store(alloca, fn_arena_ptr)
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            alloca
        };

        // m49: ret-value alloca (only for typed returns) + unified
        // fn.exit block. Every `return e;` stores into ret_alloca
        // and br's to fn.exit; void returns just br. The exit
        // epilogue runs the deep-copy + arena_destroy + ret.
        let ret_alloca = match &sig.ret {
            None => None,
            Some(ret_ty) => {
                let alloca = self.alloca_for(ret_ty, "fn.ret.slot")?;
                Some(alloca)
            }
        };
        let exit_bb = self.context.append_basic_block(func, "fn.exit");

        // v1.x-FORM-2 PR6: fallible-fn state. Allocate a local err
        // stage (Stmt::Fail writes here; epilogue sret-copies it
        // into out_err_param) and an i1 path indicator (false = ok
        // path; true = fail path). The two extra ptr params at
        // slots (params.len() + 1, +2) are the caller-provided
        // sret slots. Path defaults to ok (0) so a body that
        // never hits `fail` still has a defined path on the
        // exit-path load.
        let fallible_ctx = if let Some(payload_ty) = sig.fallible.clone() {
            let err_alloca = self.alloca_for(&payload_ty, "fn.err.slot")?;
            let bool_t = self.context.bool_type();
            let path_alloca = self
                .builder
                .build_alloca(bool_t, "fn.fail.path")
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            self.builder
                .build_store(path_alloca, bool_t.const_int(0, false))
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            let n_declared = f.params.len() as u32;
            // Slot 0 = __caller_arena; slots 1..=n_declared = user
            // params; slot n_declared+1 = out_val; slot
            // n_declared+2 = out_err.
            let out_val_param = if sig.ret.is_some() {
                Some(
                    func.get_nth_param(n_declared + 1)
                        .expect("out_val sret param")
                        .into_pointer_value(),
                )
            } else {
                None
            };
            let out_err_slot_idx =
                if sig.ret.is_some() { n_declared + 2 } else { n_declared + 1 };
            let out_err_param = func
                .get_nth_param(out_err_slot_idx)
                .expect("out_err sret param")
                .into_pointer_value();
            Some(FallibleCtx {
                err_alloca,
                path_alloca,
                out_val_param,
                out_err_param,
                payload_ty,
            })
        } else {
            None
        };

        self.current_user_fn_caller_arena = Some(caller_arena_alloca);
        self.current_user_fn_arena = Some(fn_arena_alloca);
        self.current_user_fn_exit_bb = Some(exit_bb);
        self.current_user_fn_ret_alloca = ret_alloca;
        self.current_user_fn_fallible = fallible_ctx;

        let mut scope = Scope::default();
        for (i, p) in f.params.iter().enumerate() {
            let lt = sig.params[i].clone();
            let alloca = self.alloca_for(&lt, &p.name.name)?;
            // Declared params are at LLVM slot i+1 (slot 0 is the
            // implicit __caller_arena).
            let v = func
                .get_nth_param(i as u32 + 1)
                .expect("param index in range");
            self.builder
                .build_store(alloca, v)
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            scope.locals.insert(p.name.name.clone(), (alloca, lt));
        }

        let end = self.lower_block(&f.body, &mut scope)?;
        if end == BlockEnd::Open {
            match &sig.ret {
                None => {
                    // Void fall-through: br to exit; epilogue
                    // flushes deferred-dissolves + builds
                    // `ret void`. m53: flush moved into exit so
                    // both fall-through and explicit-return
                    // paths share a single drain + dissolve
                    // sequence.
                    self.builder
                        .build_unconditional_branch(exit_bb)
                        .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
                }
                Some(_) => {
                    return Err(CodegenError::Unsupported(format!(
                        "fn `{}` falls through without returning a value",
                        f.name.name
                    )));
                }
            }
        }
        // For terminated bodies (a `return` or other terminator
        // inside the body), the Stmt::Return path already br'd to
        // exit_bb. The frame stays on the deferred_dissolves
        // stack and gets flushed by emit_fn_exit_epilogue below.

        // m49: emit the fn.exit epilogue. Position there, flush
        // the deferred-dissolves frame (drains the bus queue +
        // dissolves any loci bound in the fn body — m53), do the
        // deep-copy of ret_alloca → caller_arena (only for heap
        // types), destroy the subregion, build_return.
        self.emit_fn_exit_epilogue(&sig)?;

        self.current_fn_skip_exit_drain = prev_skip_drain;
        self.current_user_fn_caller_arena = None;
        self.current_user_fn_arena = None;
        self.current_user_fn_exit_bb = None;
        self.current_user_fn_ret_alloca = None;
        self.current_user_fn_fallible = None;
        self.current_fn = None;
        self.current_user_fn_ret = None;
        Ok(())
    }

    /// m49: emit the unified return epilogue at `fn.exit` for the
    /// fn currently being lowered. Positioned at the exit block
    /// on entry; on return, the block is closed by `build_return`.
    /// For typed-return fns, `ret_alloca` is read, deep-copied
    /// into `caller_arena`, then returned. For void fns, just
    /// destroy the subregion and `ret void`.
    fn emit_fn_exit_epilogue(
        &mut self,
        sig: &FnSig<'ctx>,
    ) -> Result<(), CodegenError> {
        let ptr_t = self.context.ptr_type(AddressSpace::default());
        let exit_bb = self
            .current_user_fn_exit_bb
            .expect("exit_bb set during fn body lowering");
        self.builder.position_at_end(exit_bb);

        let caller_arena_alloca = self
            .current_user_fn_caller_arena
            .expect("caller_arena_alloca set during fn body lowering");
        let fn_arena_alloca = self
            .current_user_fn_arena
            .expect("fn_arena_alloca set during fn body lowering");

        // v1.x-FORM-2 PR6: fallible-fn epilogue. Branches on the
        // i1 path indicator: ok path deep-copies ret_alloca into
        // the caller-provided out_val sret slot; fail path
        // deep-copies err_alloca into out_err. Both branches then
        // converge on the shared cleanup block (flush dissolves +
        // destroy subregion + `ret i1 path`). flush_dissolve_frame
        // must run exactly once, hence the unified cleanup.
        if let Some(fallible) = self.current_user_fn_fallible.clone() {
            return self.emit_fallible_fn_exit_epilogue(
                sig,
                &fallible,
                caller_arena_alloca,
                fn_arena_alloca,
            );
        }

        // Deep-copy BEFORE flush_dissolve_frame. The return value
        // can point into a let-bound sub-locus's arena (e.g. when
        // a body returns `someLocus.method(...)` directly — the
        // method allocates its concat result in its own arena);
        // flushing first frees those arenas, leaving ret_alloca
        // dangling for the str_clone read. The copy lands in
        // caller_arena, which is the parent caller's region and
        // stays alive across this fn's flush + arena_destroy
        // below. flush_dissolve_frame is a downstream operation:
        // by the time we reach it, the caller-visible value is
        // already safe in caller_arena, so dissolves can free
        // sub-locus arenas without touching what we just copied.
        //
        // FORM-3: for non-allocating bodies, the return value
        // is either a primitive (no copy needed) or a pointer to
        // a location stable across this fn's frame (either a
        // String-literal global, a caller-passed pointer, or a
        // field read of one of those). Skip the deep-copy and
        // just load the ret_alloca directly — same as the
        // non-heap-typed return path takes for primitives.
        let copied_ret: Option<BasicValueEnum<'ctx>> = match &sig.ret {
            None => None,
            Some(ret_ty) => {
                let ret_alloca = self
                    .current_user_fn_ret_alloca
                    .expect("ret_alloca set when ret type is Some");
                let llvm_ret_ty = self.llvm_basic_type(ret_ty);
                let raw_ret = self
                    .builder
                    .build_load(llvm_ret_ty, ret_alloca, "fn.ret.load")
                    .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
                if sig.non_allocating {
                    Some(raw_ret)
                } else {
                    let dest_arena = self
                        .builder
                        .build_load(ptr_t, caller_arena_alloca, "caller_arena.load")
                        .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?
                        .into_pointer_value();
                    let copied = self.emit_return_value_deep_copy(
                        raw_ret, ret_ty, dest_arena,
                    )?;
                    Some(copied)
                }
            }
        };

        // m53: free-fn handle-rooting. Flush the deferred-
        // dissolves frame opened at fn entry so any long-lived
        // loci bound in the fn body (e.g. `let _w = Watcher { };`
        // where Watcher subscribes to a bus subject) get drained
        // + dissolved before fn return. Pre-m53 the typed-return
        // path silently popped the frame without flushing,
        // leaking those handles past fn return. Per spec/memory
        // §"Free `fn` functions": "the function returns when:
        // body's last statement completes, AND all children of
        // the implicit locus have dissolved." flush_dissolve_frame
        // realizes the second clause at the codegen substrate.
        // The bus drain inside the flush dispatches any cells
        // published during the body (or by birth() of the loci
        // we're about to dissolve) before they go away. Same
        // entry point as locus-method scope-exit so the
        // semantics is uniform across all fn flavors. Runs after
        // the return-value deep-copy so freeing sub-locus arenas
        // here can't strand a String the caller is about to read.
        self.flush_dissolve_frame()?;

        // Destroy the per-call subregion AFTER the deep-copy so the
        // copy reads from valid memory. The subregion's chunk list
        // gets wholesale-freed; nothing in caller_arena is touched.
        //
        // FORM-3: skip the destroy for non-allocating bodies —
        // there's no subregion to destroy (fn_arena_alloca aliases
        // caller_arena_alloca for that path).
        if !sig.non_allocating {
            let arena_destroy = self
                .module
                .get_function("lotus_arena_destroy")
                .expect("lotus_arena_destroy declared");
            let fn_arena_loaded = self
                .builder
                .build_load(ptr_t, fn_arena_alloca, "fn.arena.load")
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            self.builder
                .build_call(
                    arena_destroy,
                    &[fn_arena_loaded.into()],
                    "fn.arena.destroy",
                )
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        }

        match copied_ret {
            None => {
                self.builder
                    .build_return(None)
                    .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            }
            Some(v) => {
                self.builder
                    .build_return(Some(&v))
                    .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            }
        }
        Ok(())
    }


    /// m49: deep-copy a fn's return value from the per-call
    /// subregion into the caller's arena. Recursive on the lotus
    /// type structure. Value types (Int/Float/Bool/Decimal-i128/
    /// Time/Duration/no-payload-Enum) are pure SSA — identity copy.
    /// String calls `lotus_str_clone(dest, src)`. Tuple allocates
    /// a fresh storage struct in `dest_arena` and recursively
    /// copies each field. Other heap-typed returns (Array,
    /// TypeRef, has-payload-Enum) reject for v0.1 — none currently
    /// appear as free-fn returns; ship as a follow-up when a
    /// workload demands.
    /// Cross-arena store anchor-in-place for **inline-storage**
    /// containers — specifically @form(hashmap).set, where the
    /// runtime memcpys the value's bytes directly into the slot
    /// (`value_size = sizeof(Cell)`). The deep-copy invariant from
    /// `d435e9b` only requires that the value's heap-pointer
    /// fields be anchored in `dest_arena` so the slot's bytes hold
    /// valid pointers after the caller's method scratch destroys.
    ///
    /// **Not** used for @form(vec).push/.set/@form(ring_buffer).push
    /// — those store pointers to structs (`elem_size = sizeof(ptr)
    /// = 8`), so the source struct itself must outlive caller
    /// scratch. They route through `emit_cross_arena_store_deep_copy_ptr`
    /// instead, which preserves the legacy fresh-outer-alloc path
    /// plus d9335bf's same-arena outer-pointer skip.
    ///
    /// Pre-rework (d9335bf) this allocated a fresh outer struct in
    /// dest_arena, walked fields into it, and returned the new
    /// pointer — the runtime then memcpy'd those bytes into the
    /// slot and the fresh allocation became immediately garbage.
    /// A downstream MetricMap residency dump pinned this:
    /// ~50 bytes wasted per `Counter.inc()` × ~128 calls/sec =
    /// 0.38 MiB/min permanent growth in the hashmap's arena, even
    /// though all 11 metric cells are registered at boot and the
    /// .set pattern carries through same-pointer String fields
    /// from `e = store.get(key)`.
    ///
    /// Anchor-in-place: walk the source struct's fields, rewrite
    /// each heap-typed field to a `dest_arena`-anchored version
    /// (via `emit_return_value_deep_copy` which routes through
    /// `lotus_str_clone` / `lotus_bytes_clone` with their existing
    /// same-arena and static-literal skips from `6a56d7c`). Leave
    /// scalar fields alone (already in the source's bytes). Return
    /// the source pointer — the runtime memcpys from there.
    ///
    /// For Counter.inc's same-arena RMW pattern, every heap field
    /// is a pointer into dest_arena already, so the per-field
    /// clones short-circuit to identity stores. Net: zero new
    /// allocations per call. For SymbolBook's pure-scalar Cell,
    /// no heap fields exist; we just return the source pointer.
    /// For genuinely new heap content (fresh String name on first
    /// metric registration), the per-field clone allocates as
    /// before — the structural cost matches what the slot will
    /// actually hold.
    ///
    /// Nested compound fields (TypeRef-in-TypeRef, Array of
    /// structs, etc.) still go through `emit_return_value_deep_copy`
    /// per field — that's necessary because the FIELD stores a
    /// pointer that must outlive caller scratch, so a fresh nested
    /// allocation in dest_arena is unavoidable. Outer-skip alone
    /// is the dominant win.
    pub(crate) fn emit_cross_arena_store_deep_copy(
        &mut self,
        value: BasicValueEnum<'ctx>,
        ty: &CodegenTy,
        dest_arena: PointerValue<'ctx>,
        site_name: &str,
    ) -> Result<BasicValueEnum<'ctx>, CodegenError> {
        match ty {
            // Scalars + views + LocusRefs + Cells: bytes/handle
            // live in the source's storage directly; no separate
            // heap-pointer to anchor.
            CodegenTy::Int
            | CodegenTy::Float
            | CodegenTy::Bool
            | CodegenTy::Decimal
            | CodegenTy::Time
            | CodegenTy::Duration
            | CodegenTy::FnPtr { .. }
            | CodegenTy::BytesView
            | CodegenTy::StringView
            | CodegenTy::LocusRef(_)
            | CodegenTy::Cell(_, _) => Ok(value),

            // String/Bytes: themselves pointers. Slot holds the
            // pointer, which must be in dest_arena (or static).
            // The clone helpers already same-arena-skip per
            // 6a56d7c — identity if already there.
            CodegenTy::String | CodegenTy::Bytes => {
                self.emit_return_value_deep_copy(value, ty, dest_arena)
            }

            // TypeRef: the dominant cell shape (user-declared
            // structs). Anchor heap-typed fields in place; leave
            // scalars untouched. Return the source pointer so the
            // runtime memcpy reads from the now-anchored bytes.
            CodegenTy::TypeRef(name) => {
                let name = name.clone();
                self.anchor_struct_fields_in_place(
                    value, &name, dest_arena, site_name,
                )
            }

            // Tuple/Array/Interface/Enum at the top level: less
            // common as cell types. Fall through to the legacy
            // outer-alloc + field-copy path. If a workload
            // surfaces these as a leak, extend the anchor-in-place
            // approach to them.
            _ => self.emit_return_value_deep_copy(value, ty, dest_arena),
        }
    }

    /// Walk a struct value's fields in-place, replacing each
    /// heap-typed field with its `dest_arena`-anchored version.
    /// Scalar and view fields are left as-is (they live in the
    /// source's storage directly). Returns the source pointer —
    /// the bytes at that pointer now hold anchored pointers
    /// suitable for memcpy into long-lived inline storage (a
    /// hashmap slot, vec buffer cell, etc.).
    ///
    /// Idempotent: a second call on the same struct sees every
    /// heap field already in dest_arena (or pointing to a static
    /// literal), so every clone short-circuits to identity. For
    /// String/Bytes the no-op comes from `lotus_str_clone`'s
    /// same-arena skip (6a56d7c). For pointer-shaped compound
    /// fields (Array, nested TypeRef, Tuple, Interface, Enum)
    /// the skip comes from the `lotus_arena_contains_ptr` gate
    /// in `emit_cross_arena_store_deep_copy_ptr`. Earlier this
    /// path went straight through `emit_return_value_deep_copy`
    /// for compound fields, which unconditionally allocates fresh
    /// storage — that was the bigcell leak the 2026-05-25 fathom
    /// kraken bench surfaced (`BookSignalState`'s two
    /// `[BookLevel; 100]` fields realloc'd on every set, ~3 KB
    /// per set × ~100 sets/sec until OOM).
    fn anchor_struct_fields_in_place(
        &mut self,
        value: BasicValueEnum<'ctx>,
        type_name: &str,
        dest_arena: PointerValue<'ctx>,
        site_name: &str,
    ) -> Result<BasicValueEnum<'ctx>, CodegenError> {
        let info = self
            .user_types
            .get(type_name)
            .cloned()
            .ok_or_else(|| {
                CodegenError::Unsupported(format!(
                    "anchor_struct_fields_in_place: unknown type `{}`",
                    type_name
                ))
            })?;
        let src_ptr = value.into_pointer_value();
        for fname in &info.field_order {
            let (idx, fty) = info
                .fields
                .get(fname)
                .cloned()
                .expect("field_order lists declared fields");
            if !Self::field_needs_anchor(&fty) {
                continue;
            }
            let field_slot = self
                .builder
                .build_struct_gep(
                    info.struct_ty,
                    src_ptr,
                    idx,
                    &format!(
                        "{}.anchor.{}.{}.ptr",
                        site_name, type_name, fname
                    ),
                )
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            // bounded[T; N] with pointer elems: anchor each live
            // slot in place (a runtime loop over [0, len)) — the
            // field is inline storage, not a loadable pointer.
            if let CodegenTy::Bounded(belem, bcap) = &fty {
                self.anchor_bounded_elems_in_place(
                    field_slot,
                    belem,
                    *bcap,
                    dest_arena,
                    &format!(
                        "{}.anchor.{}.{}",
                        site_name, type_name, fname
                    ),
                )?;
                continue;
            }
            let llvm_field_ty = self.llvm_basic_type(&fty);
            let field_val = self
                .builder
                .build_load(
                    llvm_field_ty,
                    field_slot,
                    &format!(
                        "{}.anchor.{}.{}.load",
                        site_name, type_name, fname
                    ),
                )
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
            // For String/Bytes the helper routes through
            // emit_return_value_deep_copy → lotus_str_clone, which
            // already same-arena-skips. For pointer-shaped
            // compound fields (Array, nested struct, Tuple,
            // Interface, Enum) the helper emits a runtime
            // lotus_arena_contains_ptr gate around the deep-copy
            // — identity when the field's pointer already lives in
            // dest_arena (Counter.inc RMW pattern, BookEngine
            // focus→flush RMW pattern), full deep-copy on the
            // genuinely cross-arena write (first set, fresh-cell
            // promotion).
            let anchored = self.emit_cross_arena_store_deep_copy_ptr(
                field_val,
                &fty,
                dest_arena,
                &format!("{}.anchor.{}.{}", site_name, type_name, fname),
            )?;
            self.builder
                .build_store(field_slot, anchored)
                .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        }
        Ok(value)
    }

    /// Predicate: does this field type carry a heap pointer that
    /// needs to be anchored in the destination arena? Scalars +
    /// views + locus-refs + cells don't (their bytes/handle live
    /// in the parent struct's storage). String/Bytes/TypeRef/
    /// Tuple/Interface/Enum do. Inline fixed arrays (2026-07-01,
    /// `array_inline_spec`) don't either — their element bytes are
    /// part of the parent struct's storage and travel with the
    /// parent's memcpy; loading the slot as a "pointer" would read
    /// element bytes as an address (the pre-inline walk did chase a
    /// real pointer here). Out-of-line arrays (non-scalar elements)
    /// still anchor.
    fn field_needs_anchor(ty: &CodegenTy) -> bool {
        if Self::array_inline_spec(ty).is_some() {
            return false;
        }
        // bounded[T; N]: scalar elems are inline bytes that travel
        // with the parent's memcpy — nothing to anchor. Pointer
        // elems (String/Bytes/TypeRef slots) DO anchor — the walk
        // has a dedicated live-slot loop (never load the field as
        // a single pointer).
        if let CodegenTy::Bounded(elem, _) = ty {
            return Self::bounded_elem_is_ptr(elem);
        }
        !matches!(
            ty,
            CodegenTy::Int
                | CodegenTy::Float
                | CodegenTy::Bool
                | CodegenTy::Decimal
                | CodegenTy::Time
                | CodegenTy::Duration
                | CodegenTy::FnPtr { .. }
                | CodegenTy::BytesView
                | CodegenTy::StringView
                | CodegenTy::LocusRef(_)
                | CodegenTy::Cell(_, _)
        )
    }




    /// Emit a call to a user-defined fn. Returns the lowered value
    /// + type when the fn has a return type, or `None` for void
    /// fns. Used from both expression-position and statement-position
    /// call sites.
    /// m62: lower a call to a generic free fn. Lowers each arg
    /// once (so side effects fire at most once), infers concrete
    /// type args from the resulting CodegenTys, mangles, and —
    /// if this instantiation hasn't been seen before — synthesizes
    /// + lowers a specialized fn body (saving and restoring
    /// builder state so the surrounding caller's IR isn't
    /// disturbed). Then emits a manual `build_call` using the
    /// already-lowered arg values + the implicit `__caller_arena`.
    fn lower_generic_fn_call(
        &mut self,
        name: &str,
        args: &[Expr],
        scope: &Scope<'ctx>,
    ) -> Result<Option<(BasicValueEnum<'ctx>, CodegenTy)>, CodegenError> {
        let mut arg_pairs: Vec<(BasicValueEnum<'ctx>, CodegenTy)> =
            Vec::with_capacity(args.len());
        for a in args {
            arg_pairs.push(self.lower_expr(a, scope)?);
        }
        let template = self
            .generic_fn_templates
            .get(name)
            .cloned()
            .expect("caller verified template exists");
        if arg_pairs.len() != template.params.len() {
            return Err(CodegenError::Unsupported(format!(
                "generic fn `{}` expects {} args, got {} (m62 v0.1 \
                 doesn't fill defaults on generic templates yet)",
                name,
                template.params.len(),
                arg_pairs.len()
            )));
        }
        let arg_tys: Vec<CodegenTy> =
            arg_pairs.iter().map(|(_, t)| t.clone()).collect();
        let inferred = Self::infer_generic_fn_args(&template, &arg_tys)?;
        let mangled = Self::mangle_generic_name(name, &inferred)?;

        // Synthesize + lower the specialized fn if we haven't
        // seen this instantiation before.
        if !self.user_fns.contains_key(&mangled) {
            let synth = Self::synthesize_generic_fn_instantiation(
                &template, &inferred, &mangled,
            )?;
            // Save builder state — synthesizing a fn switches
            // the insertion point to the new fn's entry block,
            // and lower_user_fn_body resets all the
            // current_user_fn_* fields. Critically also
            // save/restore `in_main`: synthesis fires while
            // lowering main's body, but the synthesized fn
            // itself isn't main and `return x` inside its body
            // must hit the typed-return path, not the exit-code
            // path. Same for `current_self` and the loop stack.
            let saved_block = self.builder.get_insert_block();
            let saved_current_fn = self.current_fn;
            let saved_user_fn_ret = self.current_user_fn_ret.clone();
            let saved_caller_arena =
                self.current_user_fn_caller_arena;
            let saved_fn_arena = self.current_user_fn_arena;
            let saved_exit_bb = self.current_user_fn_exit_bb;
            let saved_ret_alloca = self.current_user_fn_ret_alloca;
            let saved_in_main = self.in_main;
            let saved_current_self = self.current_self.clone();
            let saved_loops = std::mem::take(&mut self.loops);
            // DWARF: synthesis fires MID-STATEMENT while lowering
            // the caller — the caller's active location must not
            // leak into the synthesized fn's entry allocas
            // ("!dbg attachment points at wrong subprogram").
            // Unset for the synthesis; restore with the block.
            let saved_di_loc = self.di_current_loc.take();
            self.builder.unset_current_debug_location();

            self.in_main = false;
            self.current_self = None;

            self.declare_user_fn(&synth)?;
            self.lower_user_fn_body(&synth)?;

            // Restore caller-side state.
            if let Some(b) = saved_block {
                self.builder.position_at_end(b);
            }
            // Restore the caller's statement location (see the
            // unset above) — but never a location from another fn:
            // saved_di_loc came from the caller we're returning to.
            self.di_current_loc = saved_di_loc;
            match saved_di_loc {
                Some(loc) => {
                    self.builder.set_current_debug_location(loc)
                }
                None => self.builder.unset_current_debug_location(),
            }
            self.current_fn = saved_current_fn;
            self.current_user_fn_ret = saved_user_fn_ret;
            self.current_user_fn_caller_arena = saved_caller_arena;
            self.current_user_fn_arena = saved_fn_arena;
            self.current_user_fn_exit_bb = saved_exit_bb;
            self.current_user_fn_ret_alloca = saved_ret_alloca;
            self.in_main = saved_in_main;
            self.current_self = saved_current_self;
            self.loops = saved_loops;
        }

        // Emit the call manually using the pre-lowered args (so
        // we don't lower them twice). Mirrors lower_user_fn_call's
        // call-emit tail but without the inline arg lowering.
        let sig = self
            .user_fns
            .get(&mangled)
            .cloned()
            .expect("specialized fn was just declared");
        let caller_arena = self.current_arena_ptr()?;
        let mut llvm_args: Vec<BasicMetadataValueEnum> =
            Vec::with_capacity(sig.params.len() + 1);
        llvm_args.push(caller_arena.into());
        for (i, (val, ty)) in arg_pairs.iter().enumerate() {
            let val = if view_coerces_to(ty, &sig.params[i]) {
                // F.30b (5a): unpack view + epoch check at
                // monomorphized generic-fn arg site.
                self.unpack_view_if_needed(*val, ty)?
            } else if ty != &sig.params[i] {
                return Err(CodegenError::Unsupported(format!(
                    "generic fn `{}` arg {} type mismatch after \
                     monomorphization: expected {:?}, got {:?}",
                    mangled, i, sig.params[i], ty
                )));
            } else {
                *val
            };
            llvm_args.push(val.into());
        }
        let call = self
            .builder
            .build_call(
                sig.func,
                &llvm_args,
                &format!("{}.call", mangled),
            )
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        match sig.ret {
            None => Ok(None),
            Some(lt) => {
                let v = call
                    .try_as_basic_value()
                    .left()
                    .expect("non-void fn returns a basic value");
                Ok(Some((v, lt)))
            }
        }
    }

    /// Produce a human-readable diagnostic for a call-expression
    /// whose callee shape isn't recognized by any of the dispatch
    /// arms in lower_expr's Expr::Call lowering. The agent
    /// experience for the old "Discriminant(N)" rendering was a
    /// dead end — it didn't say what was wrong, just leaked an
    /// internal Rust enum tag. Name what we can about the callee
    /// and, for the common typo case (Ident that's close to an
    /// existing user fn), suggest a correction.
    fn diagnose_unresolved_callee(
        &self,
        callee: &Expr,
        scope: &Scope<'ctx>,
    ) -> String {
        match callee {
            Expr::Ident(i) => {
                let name = &i.name;
                let mut msg = format!(
                    "call to `{}`: no free fn / generic fn / fn-pointer \
                     binding with that name is in scope",
                    name
                );
                let candidates: Vec<&String> = self
                    .user_fns
                    .keys()
                    .chain(self.generic_fn_templates.keys())
                    .chain(scope.locals.keys())
                    .collect();
                if let Some(hit) = closest_name(name, &candidates) {
                    msg.push_str(&format!(" — did you mean `{}`?", hit));
                }
                msg
            }
            Expr::Path(qn) => {
                let p = qn
                    .segments
                    .iter()
                    .map(|s| s.name.as_str())
                    .collect::<Vec<_>>()
                    .join("::");
                format!(
                    "call to `{}`: path callee not recognized as a stdlib \
                     path or user-fn reference",
                    p
                )
            }
            Expr::Call { .. } => {
                "callee is itself a call expression (calling the result of \
                 another call is not yet supported in codegen v0 — bind the \
                 inner call's result to a `let` and call the binding)".to_string()
            }
            Expr::Field { name, .. } => format!(
                "call to method `.{}`: receiver shape not supported in \
                 expression position",
                name.name
            ),
            other => format!(
                "callee shape `{}` not supported (the callee must be a free \
                 fn name, a method-call expression, a stdlib path, or a \
                 fn-pointer binding)",
                expr_kind_label(other)
            ),
        }
    }



    /// Stage-1 FFI (2026-05-22): lower a call to an `@ffi("c")`
    /// declaration. Direct call into the LLVM-declared extern with
    /// the user-visible args only — no implicit `__caller_arena`
    /// prefix, no fallible sret slots, no monomorphization. Each
    /// arg is lowered normally then coerced to the C-ABI shape:
    /// `Bool` zero-extends to i32; views unpack to their 16-byte
    /// struct; String / Bytes pass as ptr unchanged; scalars
    /// (Int / Float / Time / Duration) pass through.
    fn lower_ffi_fn_call(
        &mut self,
        name: &str,
        sig: &FnSig<'ctx>,
        args: &[Expr],
        scope: &Scope<'ctx>,
    ) -> Result<Option<(BasicValueEnum<'ctx>, CodegenTy)>, CodegenError> {
        if args.len() != sig.params.len() {
            return Err(CodegenError::Unsupported(format!(
                "@ffi fn `{}` expects {} args, got {}",
                name,
                sig.params.len(),
                args.len()
            )));
        }
        let mut lowered_args: Vec<inkwell::values::BasicMetadataValueEnum> =
            Vec::with_capacity(args.len() + 1);
        // sret-style struct return: allocate the slot in the
        // caller's arena BEFORE the user-visible args (the
        // declaration prepended the sret ptr). The slot's pointer
        // is what the call expression yields as its value; the C
        // glue writes the struct into it during the call.
        let sret_slot: Option<(inkwell::values::PointerValue<'ctx>, String)> =
            if let Some(CodegenTy::TypeRef(type_name)) = &sig.ret {
                let info = self.user_types.get(type_name).ok_or_else(|| {
                    CodegenError::Unsupported(format!(
                        "@ffi fn `{}` return: user type `{}` not declared",
                        name, type_name
                    ))
                })?;
                let size = info.struct_ty.size_of().ok_or_else(|| {
                    CodegenError::Unsupported(format!(
                        "@ffi fn `{}` return: cannot size user type `{}`",
                        name, type_name
                    ))
                })?;
                let alloc_fn = self
                    .module
                    .get_function("lotus_arena_alloc")
                    .expect("lotus_arena_alloc declared");
                let arena = self.current_arena_ptr()?;
                let i64_t = self.context.i64_type();
                let slot = self
                    .builder
                    .build_call(
                        alloc_fn,
                        &[
                            arena.into(),
                            size.into(),
                            i64_t.const_int(16, false).into(),
                        ],
                        &format!("ffi.{}.sret_alloc", type_name),
                    )
                    .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?
                    .try_as_basic_value()
                    .left()
                    .expect("arena_alloc returns ptr")
                    .into_pointer_value();
                lowered_args.push(slot.into());
                Some((slot, type_name.clone()))
            } else {
                None
            };
        for (i, arg) in args.iter().enumerate() {
            let (val, val_ty) = self.lower_expr(arg, scope)?;
            let expected = &sig.params[i];
            if &val_ty != expected {
                return Err(CodegenError::Unsupported(format!(
                    "@ffi fn `{}` arg {}: expected {:?}, got {:?}",
                    name, i, expected, val_ty
                )));
            }
            let coerced: inkwell::values::BasicValueEnum<'ctx> =
                match expected {
                    CodegenTy::Int | CodegenTy::Duration if sig.ffi_js => {
                        // `@ffi("js")`: marshal the i64 as f64 (JS
                        // number) so the host handler doesn't receive
                        // a BigInt. Exact for |n| < 2^53.
                        let f64_t = self.context.f64_type();
                        let f = self
                            .builder
                            .build_signed_int_to_float(
                                val.into_int_value(),
                                f64_t,
                                "ffi.js.int.to_f64",
                            )
                            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
                        f.into()
                    }
                    CodegenTy::Bool => {
                        // Hale Bool lowers to LLVM i1; the C ABI
                        // table uses i32. Zero-extend at the call.
                        let i32_t = self.context.i32_type();
                        let zext = self
                            .builder
                            .build_int_z_extend(
                                val.into_int_value(),
                                i32_t,
                                "ffi.bool.zext",
                            )
                            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
                        zext.into()
                    }
                    CodegenTy::TypeRef(_) => {
                        // User-type struct passes by pointer. Hale
                        // already holds the value as a heap ptr, so
                        // pass directly. C glue dereferences:
                        //   void foo(const T *p) { use(p->field); }
                        val
                    }
                    _ => val,
                };
            lowered_args.push(coerced.into());
        }
        let call = self
            .builder
            .build_call(sig.func, &lowered_args, &format!("{}.ffi.call", name))
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        let ret_ty_opt = sig.ret.clone();
        // sret-style struct return: the LLVM call returned void
        // (the C glue wrote into the slot we passed); yield the
        // slot's pointer as the expression's value.
        if let Some((slot_ptr, _type_name)) = sret_slot {
            let ret_ty = ret_ty_opt.expect("sret_slot implies ret_ty is Some");
            return Ok(Some((slot_ptr.into(), ret_ty)));
        }
        match ret_ty_opt {
            None => Ok(None),
            Some(ret_ty) => {
                let raw = call
                    .try_as_basic_value()
                    .left()
                    .ok_or_else(|| {
                        CodegenError::Unsupported(format!(
                            "@ffi fn `{}` declared a return type but the \
                             LLVM call produced no value",
                            name
                        ))
                    })?;
                let coerced = match &ret_ty {
                    CodegenTy::Int | CodegenTy::Duration if sig.ffi_js => {
                        // `@ffi("js")` returned an f64 (JS number);
                        // narrow back to i64 (round toward zero).
                        let i64_t = self.context.i64_type();
                        let n = self
                            .builder
                            .build_float_to_signed_int(
                                raw.into_float_value(),
                                i64_t,
                                "ffi.js.f64.to_int",
                            )
                            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
                        n.into()
                    }
                    CodegenTy::Bool => {
                        // C-side returned i32; truncate back to i1
                        // for Hale's Bool ABI internally.
                        let i1_t = self.context.bool_type();
                        let trunc = self
                            .builder
                            .build_int_truncate(
                                raw.into_int_value(),
                                i1_t,
                                "ffi.bool.trunc",
                            )
                            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
                        trunc.into()
                    }
                    _ => raw,
                };
                Ok(Some((coerced, ret_ty)))
            }
        }
    }

    fn lower_user_fn_call(
        &mut self,
        name: &str,
        args: &[Expr],
        scope: &Scope<'ctx>,
    ) -> Result<Option<(BasicValueEnum<'ctx>, CodegenTy)>, CodegenError> {
        let sig = self
            .user_fns
            .get(name)
            .cloned()
            .ok_or_else(|| {
                CodegenError::Unsupported(format!("call to unknown fn `{}`", name))
            })?;
        if sig.is_ffi {
            return self.lower_ffi_fn_call(name, &sig, args, scope);
        }
        if sig.fallible.is_some() {
            return Err(CodegenError::Unsupported(format!(
                "fallible fn `{}`: call must be addressed via `or raise` / \
                 `or <expr>` / `or handler(err)`",
                name
            )));
        }
        if args.len() > sig.params.len() {
            return Err(CodegenError::Unsupported(format!(
                "fn `{}` expects at most {} args, got {}",
                name,
                sig.params.len(),
                args.len()
            )));
        }
        // Verify each missing positional slot has a default.
        for (i, default) in sig.defaults.iter().enumerate() {
            if i >= args.len() && default.is_none() {
                return Err(CodegenError::Unsupported(format!(
                    "fn `{}`: required param at position {} not \
                     provided (only {} args given)",
                    name,
                    i,
                    args.len()
                )));
            }
        }
        // m49: prepend the caller's current arena as the implicit
        // `__caller_arena` first arg. The callee opens a subregion
        // of this at body entry; its body's allocations route
        // through that subregion, and any heap-typed return value
        // gets deep-copied back into this arena before the
        // subregion is destroyed. Captured here BEFORE we lower
        // the user-visible args because lowering them is allowed
        // to allocate (e.g. building a string) and we want the
        // arena snapshot to be the call site's arena, not whatever
        // intermediate state the arg-lowering walks into.
        let caller_arena_at_call = self.current_arena_ptr()?;
        let mut llvm_args: Vec<BasicMetadataValueEnum> =
            Vec::with_capacity(sig.params.len() + 1);
        llvm_args.push(caller_arena_at_call.into());
        for i in 0..sig.params.len() {
            let (v, ty) = if i < args.len() {
                self.lower_expr(&args[i], scope)?
            } else {
                // Default expressions evaluate at the call site.
                // For const/literal defaults that's a constant; for
                // arbitrary expressions they execute in the caller's
                // scope (matching the interpreter's semantics).
                let default = sig.defaults[i].as_ref().expect("checked above");
                self.lower_expr(default, scope)?
            };
            // F.20 Phase B: implicit locus → interface coercion. If
            // the param is an Interface and the arg is a LocusRef
            // (typechecker already verified the structural impl),
            // build the fat pointer at the call site. Other type
            // mismatches still error — except Int → Float, which
            // widens via sitofp (resolves notes/hale-friction.md
            // 2026-05-10 float-surface-gaps).
            let v = if let (CodegenTy::Interface(iface), CodegenTy::LocusRef(l)) =
                (&sig.params[i], &ty)
            {
                let fat = self.coerce_to_interface(
                    v.into_pointer_value(),
                    l,
                    iface,
                )?;
                fat.into()
            } else if sig.params[i] == CodegenTy::Float && ty == CodegenTy::Int {
                let widened = self.coerce_to_float(
                    v,
                    &ty,
                    &format!("fn `{}` arg {}", name, i),
                )?;
                widened.into()
            } else if view_coerces_to(&ty, &sig.params[i]) {
                // F.30 / F.30b: BytesView → Bytes / StringView →
                // String at read-position fn-arg sites. Emits a
                // call to the unpack helper which compares the
                // view's stamped epoch against the source builder's
                // live mutation_epoch and panics on mismatch — the
                // F.30b safety net that catches "builder mutated
                // between view() and read." Returns the underlying
                // data pointer (Bytes-shaped for BytesView,
                // C-string for StringView) on the OK path.
                self.unpack_view_if_needed(v, &ty)?
            } else if ty != sig.params[i] {
                return Err(CodegenError::Unsupported(format!(
                    "fn `{}` arg {} type mismatch: expected {:?}, got {:?}",
                    name, i, sig.params[i], ty
                )));
            } else {
                v
            };
            llvm_args.push(v.into());
        }
        let call = self
            .builder
            .build_call(sig.func, &llvm_args, &format!("{}.call", name))
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        match sig.ret {
            None => Ok(None),
            Some(lt) => {
                let v = call
                    .try_as_basic_value()
                    .left()
                    .expect("non-void fn returns a basic value");
                Ok(Some((v, lt)))
            }
        }
    }


















    /// C4 (pond/crypto follow-up):
    /// `std::os::getrandom(n: Int) -> Bytes fallible(IoError)`.
    ///
    /// Calls into `lotus_os_getrandom`, which routes through the
    /// `getrandom(2)` syscall and falls back to `/dev/urandom`
    /// when the syscall is unavailable. NULL pointer → error
    /// (same convention as `read_bytes`); the `IoError.path`
    /// slot carries the static label `"std::os::getrandom"` so
    /// the agent sees which surface failed (there isn't a
    /// caller-supplied path to anchor on).
    pub(crate) fn lower_std_os_getrandom_fallible(
        &mut self,
        args: &[Expr],
        scope: &Scope<'ctx>,
    ) -> Result<FallibleCallResult<'ctx>, CodegenError> {
        if args.len() != 1 {
            return Err(CodegenError::Unsupported(format!(
                "std::os::getrandom takes 1 arg (n), got {}",
                args.len()
            )));
        }
        let (n_val, n_ty) = self.lower_expr(&args[0], scope)?;
        if n_ty != CodegenTy::Int {
            return Err(CodegenError::Unsupported(format!(
                "std::os::getrandom: n must be Int, got {:?}",
                n_ty
            )));
        }
        let f = self
            .module
            .get_function("lotus_os_getrandom")
            .expect("lotus_os_getrandom declared");
        let bytes_ptr = self
            .builder
            .build_call(f, &[n_val.into()], "os.getrandom.ret")
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?
            .try_as_basic_value()
            .left()
            .expect("lotus_os_getrandom returns ptr")
            .into_pointer_value();
        // NULL => error (errno is set by the runtime).
        let is_err = self
            .builder
            .build_int_compare(
                inkwell::IntPredicate::EQ,
                self.builder
                    .build_ptr_to_int(
                        bytes_ptr,
                        self.context.i64_type(),
                        "os.getrandom.as_int",
                    )
                    .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?,
                self.context.i64_type().const_zero(),
                "os.getrandom.is_err",
            )
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        // Anchor the diagnostic path on the surface name — no
        // caller-supplied path here, but the agent still benefits
        // from seeing *which* fallible primitive raised.
        let path_label = self
            .builder
            .build_global_string_ptr("std::os::getrandom", "os.getrandom.label")
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?
            .as_pointer_value();
        self.complete_io_fallible_call(
            is_err,
            path_label.into(),
            Some((bytes_ptr.into(), CodegenTy::Bytes)),
            "os.getrandom",
        )
    }




































    /// Open-question #24 MVP (2026-05-25): the user-declared
    /// fallible method dispatch. Resolves `method_name` on
    /// `locus_name`'s AST, validates the FnDecl is marked
    /// fallible, then emits the call with the same sret-slot
    /// shape free-fn fallible calls use minus the
    /// `__caller_arena` prefix. Returns `Ok(None)` (caller
    /// falls through to the unsupported diagnostic) if the
    /// method is not declared or not fallible — preserves the
    /// existing surrounding error path for stale-name shapes
    /// rather than masking them.
    pub(crate) fn try_lower_user_locus_fallible_method(
        &mut self,
        info: &LocusInfo<'ctx>,
        self_ptr: PointerValue<'ctx>,
        locus_name: &str,
        method_name: &str,
        args: &[Expr],
        scope: &Scope<'ctx>,
    ) -> Result<Option<FallibleCallResult<'ctx>>, CodegenError> {
        let Some(func) = info.user_methods.get(method_name).copied() else {
            return Ok(None);
        };
        // Find the FnDecl so we can consult its fallible
        // declaration + param list. Mode-method decls also live
        // in user_methods, but mode methods don't carry
        // `fallible` (the parser doesn't accept it on modes),
        // so we'd miss them naturally.
        let fd_opt: Option<FnDecl> =
            self.program.items.iter().find_map(|item| match item {
                TopDecl::Locus(l) if l.name.name == locus_name => l
                    .members
                    .iter()
                    .find_map(|m| match m {
                        LocusMember::Fn(fd) if fd.name.name == method_name => {
                            Some(fd.clone())
                        }
                        _ => None,
                    }),
                _ => None,
            });
        let Some(fd) = fd_opt else { return Ok(None) };
        let Some(payload_te) = &fd.fallible else {
            return Ok(None);
        };

        let payload_ty = self.type_expr_to_codegen_ty(payload_te)?;
        // A2 (G2): normalize `-> ()` to None — same Unit-success
        // shape the declare and body paths use.
        let ret_te_normalized: Option<&TypeExpr> = match &fd.ret {
            Some(TypeExpr::Tuple(parts, _)) if parts.is_empty() => None,
            other => other.as_ref(),
        };
        let success_ty: Option<CodegenTy> = match ret_te_normalized {
            None => None,
            Some(t) => Some(self.type_expr_to_codegen_ty(t)?),
        };

        // Arg count check. Default-value omission is supported
        // for fallible locus methods on the same suffix-only
        // basis as non-fallible ones — but for MVP we require
        // exact-arg count to keep the dispatch simple. The
        // typechecker already validates argument arity; this
        // is defense.
        if args.len() != fd.params.len() {
            return Err(CodegenError::Unsupported(format!(
                "locus `{}` method `{}`: fallible call expects {} args, \
                 got {}",
                locus_name,
                method_name,
                fd.params.len(),
                args.len()
            )));
        }

        // Allocate sret slots before lowering args, so the
        // alloca lands in the entry block (LLVM mem2reg
        // discipline) and slot pointers stay stable across arg
        // lowering.
        let out_val_slot: Option<PointerValue<'ctx>> = match &success_ty {
            Some(st) => Some(self.alloca_for(st, "method.or.out_val.slot")?),
            None => None,
        };
        let out_err_slot =
            self.alloca_for(&payload_ty, "method.or.out_err.slot")?;

        // Lower args + assemble call args. Slot 0 = self_ptr;
        // slots 1..=n = user params; tail sret slots.
        let mut llvm_args: Vec<BasicMetadataValueEnum<'ctx>> =
            Vec::with_capacity(args.len() + 3);
        llvm_args.push(self_ptr.into());
        for (i, a) in args.iter().enumerate() {
            let want = self.type_expr_to_codegen_ty(&fd.params[i].ty)?;
            let (v, got) = self.lower_expr(a, scope)?;
            let v = if got != want {
                if view_coerces_to(&got, &want) {
                    self.unpack_view_if_needed(v, &got)?
                } else {
                    return Err(CodegenError::Unsupported(format!(
                        "locus `{}` method `{}`: arg {} type mismatch: \
                         expected {:?}, got {:?}",
                        locus_name, method_name, i, want, got
                    )));
                }
            } else {
                v
            };
            llvm_args.push(v.into());
        }
        if let Some(slot) = &out_val_slot {
            llvm_args.push((*slot).into());
        }
        llvm_args.push(out_err_slot.into());

        // Open-question #24 v0.2: publish the caller's current
        // arena via TLS before invoking the fallible method.
        // The callee's `open_method_scratch` snapshots it at
        // body entry, and the epilogue's deep-copy lands the
        // ok/fail payload back in this arena before the
        // callee's scratch is destroyed. Mirrors the non-
        // fallible heap-returning method call discipline.
        self.emit_set_caller_arena()?;
        let call = self
            .builder
            .build_call(
                func,
                &llvm_args,
                &format!("{}.{}.fallible.call", locus_name, method_name),
            )
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        let i1_path = call
            .try_as_basic_value()
            .left()
            .expect("fallible method returns i1")
            .into_int_value();

        Ok(Some(FallibleCallResult {
            i1_path,
            out_val_slot,
            out_err_slot,
            success_ty,
            payload_ty,
        }))
    }




    /// 2026-05-16: lower `@form(hashmap).key_at(i)` /
    /// `entry_at(i)`. Each takes an `Int` and returns
    /// `fallible(IndexError)`. The C primitive (lotus_hashmap_
    /// key_at / value_at) walks the slots array counting occupied
    /// entries; the wrapper inverts the bool into an i1 error
    /// path and lazy-emits the IndexError on the miss side.
    #[allow(clippy::too_many_arguments)]

    /// v1.x-FORM-2 PR6 (PR5 finale): allocate an `IndexError`
    /// struct in the current arena and populate its three fields.
    /// Matches the shape `inject_form_stdlib_types` synthesizes
    /// (`kind: String`, `index: Int`, `len: Int`) and the
    /// interpreter's `index_error_value` helper.
    pub(crate) fn emit_index_error_alloc(
        &mut self,
        kind: &str,
        index_ssa: IntValue<'ctx>,
        len_ssa: IntValue<'ctx>,
    ) -> Result<PointerValue<'ctx>, CodegenError> {
        let info = self
            .user_types
            .get("IndexError")
            .cloned()
            .expect("IndexError injected by hale-types resolver");
        let size = info
            .struct_ty
            .size_of()
            .expect("IndexError has known size");
        let alloc_ptr = self.arena_alloc(size, "IndexError.alloc")?;

        let kind_str_ptr = self.global_string(kind);
        let (kind_idx, _) = info
            .fields
            .get("kind")
            .cloned()
            .expect("IndexError.kind field");
        let kind_field_ptr = self
            .builder
            .build_struct_gep(
                info.struct_ty,
                alloc_ptr,
                kind_idx,
                "IndexError.kind.ptr",
            )
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        self.builder
            .build_store(kind_field_ptr, kind_str_ptr)
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;

        let (index_idx, _) = info
            .fields
            .get("index")
            .cloned()
            .expect("IndexError.index field");
        let index_field_ptr = self
            .builder
            .build_struct_gep(
                info.struct_ty,
                alloc_ptr,
                index_idx,
                "IndexError.index.ptr",
            )
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        self.builder
            .build_store(index_field_ptr, index_ssa)
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;

        let (len_idx, _) = info
            .fields
            .get("len")
            .cloned()
            .expect("IndexError.len field");
        let len_field_ptr = self
            .builder
            .build_struct_gep(
                info.struct_ty,
                alloc_ptr,
                len_idx,
                "IndexError.len.ptr",
            )
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;
        self.builder
            .build_store(len_field_ptr, len_ssa)
            .map_err(|e| CodegenError::LlvmEmit(e.to_string()))?;

        Ok(alloc_ptr)
    }

